下面给出一份 可编译思路 的精简实现：创建订单流水线——校验 → 加载商品行 → 预留库存 → 写单。 package orderpipe import ( "context" "errors" "fmt"
) // OrderPipeContext 承载一次「创单」流水线的输入与中间态。
type OrderPipeContext struct { Req PlaceOrderRequest ResolvedLines []OrderLine ReservationID string CreatedOrderID string
} type PlaceOrderRequest struct { CustomerID string Lines []LineRequest
} type LineRequest struct { SKU string Qty int
} type OrderLine struct { SKU string Qty int UnitCents int64
} // Processor 单步处理逻辑。
type Processor interface { Name() string Process(ctx context.Context, c *OrderPipeContext) error
} // Pipeline 顺序执行。
type Pipeline struct { steps []Processor
} func NewPipeline(steps ...Processor) *Pipeline { return &Pipeline{steps: steps}
} func (p *Pipeline) Run(ctx context.Context, c *OrderPipeContext) error { for _, s := range p.steps { if err := ctx.Err(); err != nil { return err } if err := s.Process(ctx, c); err != nil { return fmt.Errorf("%s: %w", s.Name(), err) } } return nil
} // --- Processors --- type validateProcessor struct{} func (validateProcessor) Name() string { return "validate" } func (validateProcessor) Process(_ context.Context, c *OrderPipeContext) error { if c.Req.CustomerID == "" { return errors.New("customer_id required") } if len(c.Req.Lines) == 0 { return errors.New("at least one line") } return nil
} type Catalog interface { ResolveLines(ctx context.Context, lines []LineRequest) ([]OrderLine, error)
} type resolveCatalogProcessor struct{ cat Catalog } func (p resolveCatalogProcessor) Name() string { return "resolve_catalog" } func (p resolveCatalogProcessor) Process(ctx context.Context, c *OrderPipeContext) error { lines, err := p.cat.ResolveLines(ctx, c.Req.Lines) if err != nil { return err } c.ResolvedLines = lines return nil
} type Inventory interface { Reserve(ctx context.Context, customerID string, lines []OrderLine) (reservationID string, err error)
} type reserveInventoryProcessor struct{ inv Inventory } func (p reserveInventoryProcessor) Name() string { return "reserve_inventory" } func (p reserveInventoryProcessor) Process(ctx context.Context, c *OrderPipeContext) error { rid, err := p.inv.Reserve(ctx, c.Req.CustomerID, c.ResolvedLines) if err != nil { return err } c.ReservationID = rid return nil
} type OrderRepository interface { Insert(ctx context.Context, c *OrderPipeContext) (orderID string, err error)
} type persistOrderProcessor struct{ repo OrderRepository } func (p persistOrderProcessor) Name() string { return "persist_order" } func (p persistOrderProcessor) Process(ctx context.Context, c *OrderPipeContext) error { id, err := p.repo.Insert(ctx, c) if err != nil { return err } c.CreatedOrderID = id return nil
} 组装处（例如在 cmd 或 application 包）一眼读完流程 ： func NewPlaceOrderPipeline(cat Catalog, inv Inventory, repo OrderRepository) *Pipeline { return NewPipeline( validateProcessor{}, resolveCatalogProcessor{cat: cat}, reserveInventoryProcessor{inv: inv}, persistOrderProcessor{repo: repo}, )
}

