package stockstrategy import ( "context" "errors" "fmt"
) type ReserveInput struct { SKU string Qty int
} // Reserver 库存预留策略。
type Reserver interface { Kind() string Reserve(ctx context.Context, in ReserveInput) error
} type Registry struct { byKind map[string]Reserver
} func NewRegistry(rs ...Reserver) (*Registry, error) { m := make(map[string]Reserver, len(rs)) for _, r := range rs { k := r.Kind() if _, dup := m[k]; dup { return nil, fmt.Errorf("duplicate reserver: %s", k) } m[k] = r } return &Registry{byKind: m}, nil
} func (reg *Registry) Reserve(ctx context.Context, kind string, in ReserveInput) error { r, ok := reg.byKind[kind] if !ok { return errors.New("unknown stock kind") } return r.Reserve(ctx, in)
}

