type platformReserver struct{} func (platformReserver) Kind() string { return "platform" } func (platformReserver) Reserve(ctx context.Context, in ReserveInput) error { // 调用平台自有库存服务（Redis + DB 等） _ = ctx if in.Qty <= 0 { return errors.New("qty must be positive") } return nil
} type vendorRealtimeReserver struct{} func (vendorRealtimeReserver) Kind() string { return "vendor_realtime" } func (vendorRealtimeReserver) Reserve(ctx context.Context, in ReserveInput) error { // 同步调用供应商库存 API _ = ctx return nil
} type vendorAsyncReserver struct{} func (vendorAsyncReserver) Kind() string { return "vendor_async" } func (vendorAsyncReserver) Reserve(ctx context.Context, in ReserveInput) error { // 写入待同步队列，由异步任务向供应商确认 _ = ctx _ = in return nil
} classDiagram class Reserver { <<interface>> +Kind() string +Reserve(ctx, in) error } Reserver <|.. platformReserver Reserver <|.. vendorRealtimeReserver Reserver <|.. vendorAsyncReserver Registry --> Reserver : lookup by kind 与 Pipeline 的分工 ：Pipeline 回答「 先做啥后做啥 」；策略回答「 同一类步骤里用哪套算法 」。例如「预留库存」这一步内部再根据 kind 选策略。

