核心思想： 规则 = 条件（数据） + 动作（数据） ，引擎负责排序、匹配、互斥与累计。下面示例用内存规则列表演示；生产可替换为从 DB 加载并带版本号缓存。 package rules import ( "context" "errors" "fmt" "sort" "time"
) type MarketingContext struct { Now time.Time NewUser bool Subtotal int64 // 分 VIPLevel int Category string
} type Effect struct { RuleID int RuleName string Discount int64 // 分，正数表示扣减应付
} type Rule struct { ID int Name string Priority int Enabled bool Start, End time.Time MutexWith []int When func(MarketingContext) bool Apply func(*MarketingContext, *Evaluation) error
} type Evaluation struct { Applied []Effect used map[int]struct{}
} func NewEvaluation() *Evaluation { return &Evaluation{used: make(map[int]struct{})}
} func (e *Evaluation) markUsed(id int) { e.used[id] = struct{}{}
} func (e *Evaluation) hasUsedAny(ids []int) bool { for _, id := range ids { if _, ok := e.used[id]; ok { return true } } return false
} type Engine struct { rules []*Rule
} func NewEngine(r ...*Rule) *Engine { rs := append([]*Rule(nil), r...) sort.Slice(rs, func(i, j int) bool { return rs[i].Priority > rs[j].Priority }) return &Engine{rules: rs}
} func (eng *Engine) Evaluate(ctx context.Context, mc MarketingContext) (*Evaluation, error) { _ = ctx out := NewEvaluation() for _, rule := range eng.rules { if !rule.Enabled { continue } if mc.Now.Before(rule.Start) || mc.Now.After(rule.End) { continue } if out.hasUsedAny(rule.MutexWith) { continue } if rule.When == nil || !rule.When(mc) { continue } out.Applied = append(out.Applied, Effect{RuleID: rule.ID, RuleName: rule.Name}) if err := rule.Apply(&mc, out); err != nil { out.Applied = out.Applied[:len(out.Applied)-1] return nil, fmt.Errorf("rule %d: %w", rule.ID, err) } out.markUsed(rule.ID) } return out, nil
}

