下面给出一个 教学裁剪版 但 结构完整 的 Go 示例：三步正向（计价快照绑定、库存预占、营销锁定）与两步补偿（释放库存、解锁营销）。示例省略了真实 RPC、链路追踪与部分错误包装，但保留 编排骨架、幂等键透传、补偿逆序 等关键结构。 Saga 流程图 ： flowchart TD Start([开始 CreateOrderSaga]) --> T1[Step1: AttachPriceSnapshot] T1 -->|失败| X1([结束: 失败无补偿]) T1 -->|成功| T2[Step2: ReserveInventory] T2 -->|失败| C1[Comp1: 无需库存补偿] T2 -->|成功| T3[Step3: LockMarketing] T3 -->|失败| C2[Comp2: ReleaseInventory] T3 -->|成功| Done([持久化订单\n提交本地事务]) C2 --> X2([结束: 已回滚库存]) style Done fill:#e8f5e9 style X1 fill:#ffebee style X2 fill:#fff3e0 Go 编排骨架 （单文件可 go run，将下游调用替换为真实 gRPC / HTTP SDK 即可落地）： Walk-through（对照流程图读代码） ： AttachSnapshot 失败时，系统尚未占用库存与营销资源，因此直接返回错误即可，对应流程图左侧「失败无补偿」分支。 Reserve 成功后，reserve_id 成为库存侧的 外部凭证 ；后续任何释放都必须携带它，并在库存服务侧以幂等方式处理。 LockPromo 失败进入补偿：只释放库存，不解锁营销（因为锁未成功）。若未来某版本 LockPromo 变成「部分成功」（例如锁定成功但写审计失败），必须把补偿扩展为「先查锁是否存在再解锁」，否则会出现补偿空转或补偿遗漏。 Run 成功后，订单服务应在 单一本地事务 中写入订单主表、明细、价格快照引用、外部凭证集合，并写入 Outbox 触发下游投影。不要把「订单持久化」拆到多个没有事务边界的 RPC 里，否则你会重新发明分布式事务。 package main import ( "context" "errors" "fmt" "log" "net/http" "time"
) // ---- 端口：生产环境应使用 gRPC / 生成代码 ---- type PricingClient interface { AttachSnapshot(ctx context.Context, orderID, snapshotID string) error
} type InventoryClient interface { Reserve(ctx context.Context, idempotencyKey, orderID, sku string, qty int) (reserveID string, err error) Release(ctx context.Context, idempotencyKey, reserveID string) error
} type MarketingClient interface { LockPromo(ctx context.Context, idempotencyKey, orderID, promoRef string) (lockID string, err error) UnlockPromo(ctx context.Context, idempotencyKey, lockID string) error
} // ---- 编排器 ---- type CreateOrderCommand struct { OrderID string IdempotencyKey string PriceSnapshot string SKU string Qty int PromoRef string
} type CreateOrderSaga struct { Pricing PricingClient Inventory InventoryClient Marketing MarketingClient
} func (s *CreateOrderSaga) Run(ctx context.Context, cmd CreateOrderCommand) error { if cmd.OrderID == "" || cmd.IdempotencyKey == "" { return errors.New("invalid command") } // Step 1: 绑定计价快照（失败则无资源占用） if err := s.Pricing.AttachSnapshot(ctx, cmd.OrderID, cmd.PriceSnapshot); err != nil { return fmt.Errorf("attach snapshot: %w", err) } // Step 2: 库存预占 reserveID, err := s.Inventory.Reserve(ctx, cmd.IdempotencyKey+":inv", cmd.OrderID, cmd.SKU, cmd.Qty) if err != nil { return fmt.Errorf("reserve inventory: %w", err) } // Step 3: 营销锁定 lockID, err := s.Marketing.LockPromo(ctx, cmd.IdempotencyKey+":mkt", cmd.OrderID, cmd.PromoRef) if err != nil { // 补偿：释放库存（逆序） if relErr := s.Inventory.Release(ctx, cmd.IdempotencyKey+":inv:rel", reserveID); relErr != nil { return fmt.Errorf("lock promo failed: %v; release inventory failed: %w", err, relErr) } return fmt.Errorf("lock promo: %w", err) } log.Printf("saga ok order=%s reserve=%s lock=%s", cmd.OrderID, reserveID, lockID) // Step 4（示意）：在同一服务的数据库事务里插入订单主表与明细 return nil
} // ---- 内存桩：演示幂等 + 成功路径 ---- type memPricing struct{} func (memPricing) AttachSnapshot(ctx context.Context, orderID, snapshotID string) error { return nil
} type memInventory struct { released bool
} func (m *memInventory) Reserve(ctx context.Context, idempotencyKey, orderID, sku string, qty int) (string, error) { return "resv_123", nil
} func (m *memInventory) Release(ctx context.Context, idempotencyKey, reserveID string) error { m.released = true return nil
} type memMarketing struct{} func (memMarketing) LockPromo(ctx context.Context, idempotencyKey, orderID, promoRef string) (string, error) { return "lock_456", nil
} func (memMarketing) UnlockPromo(ctx context.Context, idempotencyKey, lockID string) error { return nil
} // 将 HTTP 客户端映射为 InventoryClient 的示例（真实项目用专用 SDK）
type httpInventory struct { client *http.Client url string
} func (httpInventory) Reserve(ctx context.Context, idempotencyKey, orderID, sku string, qty int) (string, error) { // 伪代码：构造 POST /v1/reservations，Header 携带 Idempotency-Key return "", errors.New("not implemented in demo")
} func (httpInventory) Release(ctx context.Context, idempotencyKey, reserveID string) error { return errors.New("not implemented in demo")
} func main() { ctx, cancel := context.WithTimeout(context.Background(), 2*time.Second) defer cancel() saga := &CreateOrderSaga{ Pricing: memPricing{}, Inventory: &memInventory{}, Marketing: memMarketing{}, } err := saga.Run(ctx, CreateOrderCommand{ OrderID: "ord_1", IdempotencyKey: "idem_user_click_001", PriceSnapshot: "pshot_9f3c", SKU: "sku_a", Qty: 1, PromoRef: "promo_x", }) if err != nil { log.Fatal(err) }
} 落地清单（从示例走向生产） ： 为每一步引入 持久化 Saga 表 （saga_id、step、status、payload、error_code）。 所有 outbound 调用携带 关联 ID （order_id、trace_id、idempotency_key）。 对「超时未知」统一走 query + reconcile 状态机，而不是立刻补偿。 Saga 表结构示例（MySQL，示意） ：落地时按你们公司的审计规范补全操作者与 trace 字段。 CREATE TABLE saga_instance ( saga_id BIGINT PRIMARY KEY AUTO_INCREMENT, biz_key VARCHAR(128) NOT NULL, name VARCHAR(64) NOT NULL, status VARCHAR(32) NOT NULL, current_step INT NOT NULL, payload JSON NOT NULL, version INT NOT NULL DEFAULT 0, created_at DATETIME NOT NULL, updated_at DATETIME NOT NULL, UNIQUE KEY uk_saga_biz (biz_key, name)
); CREATE TABLE saga_step ( id BIGINT PRIMARY KEY AUTO_INCREMENT, saga_id BIGINT NOT NULL, step_no INT NOT NULL, step_name VARCHAR(64) NOT NULL, status VARCHAR(32) NOT NULL, req JSON, resp JSON, err TEXT, created_at DATETIME NOT NULL, KEY idx_saga (saga_id, step_no)
);

