Outbox 模式 解决的核心矛盾是： 数据库事务提交 与 消息发布 难以跨资源原子化。做法是：在同一本地事务中写入业务表与 outbox 表；由独立进程异步投递到消息总线，实现 at-least-once 发布且 不丢单 （消费者仍需幂等）。 Outbox 时序图 ： sequenceDiagram participant API as Order API participant DB as MySQL participant R as Outbox Relay participant K as Kafka API->>DB: BEGIN API->>DB: INSERT orders ... API->>DB: INSERT outbox(event_type,payload,status) API->>DB: COMMIT loop poll R->>DB: SELECT ... FOR UPDATE SKIP LOCKED R->>K: produce message(idempotent key) K-->>R: ack R->>DB: UPDATE outbox SET status=published end Go 实现骨架 （使用 database/sql；生产环境可替换为 sqlx / ORM，但保持「同事务写两张表」不变）： package outboxdemo import ( "context" "database/sql" "encoding/json" "time"
) type OutboxEvent struct { ID int64 Aggregate string EventType string Payload json.RawMessage Status string // pending / published / dead CreatedAt time.Time
} type OrderRepository struct { DB *sql.DB
} // CreateOrderWithOutbox 演示：订单写入与 outbox 同事务
func (r *OrderRepository) CreateOrderWithOutbox(ctx context.Context, orderID string, evtType string, payload any) error { bytes, err := json.Marshal(payload) if err != nil { return err } tx, err := r.DB.BeginTx(ctx, &sql.TxOptions{Isolation: sql.LevelReadCommitted}) if err != nil { return err } defer func() { _ = tx.Rollback() }() if _, err := tx.ExecContext(ctx, `INSERT INTO orders(id, status) VALUES(?, 'CREATED')`, orderID); err != nil { return err } if _, err := tx.ExecContext(ctx, `INSERT INTO outbox(aggregate_id, event_type, payload, status, created_at) VALUES(?,?,?,?,?)`, orderID, evtType, bytes, "pending", time.Now().UTC(), ); err != nil { return err } return tx.Commit()
} // Relay 轮询投递：演示 SKIP LOCKED 多实例安全
type Relay struct { DB *sql.DB
} func (relay *Relay) PollOnce(ctx context.Context, publish func(ctx context.Context, ev OutboxEvent) error) (int, error) { tx, err := relay.DB.BeginTx(ctx, nil) if err != nil { return 0, err } defer func() { _ = tx.Rollback() }() rows, err := tx.QueryContext(ctx, ` SELECT id, aggregate_id, event_type, payload, status, created_at FROM outbox WHERE status='pending' ORDER BY id ASC LIMIT 50 FOR UPDATE SKIP LOCKED`) if err != nil { return 0, err } defer rows.Close() var batch []OutboxEvent for rows.Next() { var ev OutboxEvent var agg string if err := rows.Scan(&ev.ID, &agg, &ev.EventType, &ev.Payload, &ev.Status, &ev.CreatedAt); err != nil { return 0, err } ev.Aggregate = agg batch = append(batch, ev) } if len(batch) == 0 { return 0, tx.Commit() } for _, ev := range batch { if err := publish(ctx, ev); err != nil { return 0, err } if _, err := tx.ExecContext(ctx, `UPDATE outbox SET status='published' WHERE id=?`, ev.ID); err != nil { return 0, err } } return len(batch), tx.Commit()
} func DemoDDL() string { return `
CREATE TABLE IF NOT EXISTS orders ( id VARCHAR(64) PRIMARY KEY, status VARCHAR(32) NOT NULL
);
CREATE TABLE IF NOT EXISTS outbox ( id BIGINT PRIMARY KEY AUTO_INCREMENT, aggregate_id VARCHAR(64) NOT NULL, event_type VARCHAR(128) NOT NULL, payload JSON NOT NULL, status VARCHAR(16) NOT NULL, created_at DATETIME NOT NULL, KEY idx_outbox_pending (status, id)
);`
} 工程清单 ： Relay 进程要 独立扩容 ，与 API 进程分离；发布失败应 退避重试 并将多次失败送入死信队列人工处理。 消息体应携带 event_id / aggregate_id / causation_id ，与消费者表上的唯一约束联合实现端到端幂等。 与第 16 章「事件发布」衔接时，把 事件契约 （JSON Schema / Protobuf）纳入 CI，避免「字段悄悄改名」造成投影脏写。 Outbox 运维要点 ：pending 堆积通常不是 Kafka 坏了，而是 Relay 吞吐不足、DB 锁竞争、或下游拒绝消息 。建议把以下指标做成仪表盘：outbox_pending_count、relay_lag_seconds、publish_fail_rate、dead_letter_count。出现持续堆积时，优先扩容 Relay 与检查热点 aggregate_id（大单事件风暴）。 顺序投递 vs 批量投递 ：某些支付相关事件需要严格顺序，Relay 可以按 aggregate_id 分区串行投递；而搜索增量可批量合并，降低总线开销。关键是不要把「所有事件都塞进一个全局顺序」里，否则系统吞吐会被最慢的消费者绑架。 与第 1 章 Outbox 小节的关系 ：第 1 章强调「领域事件异步化」的动机与边界；本章补齐 实现骨架、时序与运维指标 ，便于你在第 7–15 章落地到具体服务时直接对照检查清单。

