策略模式适合放在 「写路径规则选择」 ：例如校验、规格展开、搜索文档 enrich、库存维度声明。下面示例展示 注册表 + 显式策略接口 ，避免核心服务直接依赖具体品类包（可拆插件模块）。 type ProductKind string const ( KindStandard ProductKind = "standard" KindVirtual ProductKind = "virtual" KindService ProductKind = "service" KindBundle ProductKind = "bundle"
) // GovernanceStrategy：异构治理策略（写路径/建模路径）
type GovernanceStrategy interface { Kind() ProductKind Validate(spu *SPU, skus []*SKU) error EnrichSearchDoc(doc *SearchDoc, spu *SPU, skus []*SKU) StockDimensions() []string
} type SearchDoc struct { SPUID string Title string CategoryID int64 Tags []string Extra map[string]string
} type standardStrategy struct{} func (standardStrategy) Kind() ProductKind { return KindStandard } func (standardStrategy) Validate(spu *SPU, skus []*SKU) error { if len(skus) == 0 { return ErrSKUsRequired } return nil
} func (standardStrategy) EnrichSearchDoc(doc *SearchDoc, spu *SPU, skus []*SKU) { doc.Tags = append(doc.Tags, "physical")
} func (standardStrategy) StockDimensions() []string { return []string{"warehouse_sku"} } type serviceStrategy struct{} func (serviceStrategy) Kind() ProductKind { return KindService } func (serviceStrategy) Validate(spu *SPU, skus []*SKU) error { // 允许 SKU 对应房型等；库存走日历维度（库存系统） return nil
} func (serviceStrategy) EnrichSearchDoc(doc *SearchDoc, spu *SPU, skus []*SKU) { doc.Extra["inventory_profile"] = "calendar" doc.Tags = append(doc.Tags, "service")
} func (serviceStrategy) StockDimensions() []string { return []string{"date", "room_type"} } type StrategyRegistry struct { byKind map[ProductKind]GovernanceStrategy
} func NewStrategyRegistry() *StrategyRegistry { r := &StrategyRegistry{byKind: map[ProductKind]GovernanceStrategy{}} r.Register(standardStrategy{}) r.Register(serviceStrategy{}) // virtual/bundle 同理注册 return r
} func (r *StrategyRegistry) Register(s GovernanceStrategy) { r.byKind[s.Kind()] = s
} func (r *StrategyRegistry) Resolve(spu *SPU) GovernanceStrategy { k := ProductKind(spu.ProductType) if s, ok := r.byKind[k]; ok { return s } return r.byKind[KindStandard]
} // UpsertSPU 演示策略介入点：校验 + 搜索投影 enrich
func UpsertSPU(ctx context.Context, reg *StrategyRegistry, repo ProductRepository, spu *SPU, skus []*SKU) error { st := reg.Resolve(spu) if err := st.Validate(spu, skus); err != nil { return err } if err := repo.SaveSPUAndSKUs(ctx, spu, skus); err != nil { return err } doc := &SearchDoc{SPUID: spu.SPUID, Title: spu.Title, CategoryID: spu.CategoryID, Extra: map[string]string{}} st.EnrichSearchDoc(doc, spu, skus) return PublishSearchUpsert(ctx, doc)
} classDiagram class GovernanceStrategy { <<interface>> +Kind() ProductKind +Validate(spu, skus) error +EnrichSearchDoc(doc, spu, skus) +StockDimensions() []string } class StrategyRegistry { -byKind map +Register(s) +Resolve(spu) GovernanceStrategy } class standardStrategy class serviceStrategy GovernanceStrategy <|.. standardStrategy GovernanceStrategy <|.. serviceStrategy StrategyRegistry o-- GovernanceStrategy : resolves 与适配器的边界 ：适配器解决 外部形状不一致 ；策略解决 内部规则不一致 。二者可组合：同步适配器产出平台 SPU，再进入策略校验。 配置化平台的边界 ：表单、步骤、审核模板配置能显著加快新品类接入，但不要把「强业务规则」无限制脚本化到运营可编辑，否则难以测试与回滚。建议把规则分级： L1 配置 （字段/枚举/展示）运营可改； L2 规则 （库存维度声明、搜索 enrich）需要发布评审； L3 代码 （复杂约束、组合分摊）必须走研发变更。 组合商品补充 ：组合 SPU 的子项引用建议存「子 spu_id + 子 sku_id + 数量」，并在策略层实现 联合校验 （子品任一不可售则父不可售）。组合售价分摊属于计价/订单域更合适；商品中心可提供「子品结构事实」(BOM)，但不负责最终金额计算。

