推荐策略： 创单前 ：订单服务向商品中心请求 CreateSnapshot(spu_id, sku_id)，返回 snapshot_id。 内容寻址 ：对快照正文做规范化序列化（稳定 key 排序）后计算哈希；哈希即 snapshot_id（或映射到 UUID）。 并发创建 ：数据库层对 snapshot_id 做唯一约束，插入冲突则直接返回已存在记录。 与计价快照的衔接 ：商品快照建议只固化 展示相关字段 （标题、图、规格文本、基础属性）。若把促销价、券后价写入商品快照，会与营销域频繁变化纠缠，复用率也会骤降。更干净的做法是：订单表同时引用 product_snapshot_id 与 pricing_snapshot_id（或等价结构），客服展示时组合渲染。 版本字段 ：除内容哈希外，可增加 spu_version 字段写入快照正文，用于快速判断「商品中心是否发生过大版本回滚」；但它不应替代哈希作为主键，否则会出现「内容相同但版本号不同导致无法复用」的浪费。 import ( "context" "crypto/sha256" "encoding/hex" "encoding/json" "time"
) type ProductSnapshot struct { SnapshotID string // content hash SPUID string SKUID string BodyJSON string ContentHash string CreatedAt int64
} type SnapshotInput struct { SPU *SPU SKU *SKU AttrDisplay map[int64]string // 已解析展示属性
} func stableJSON(v any) (string, error) { // 使用稳定序列化：sort keys，避免 map 迭代顺序导致 hash 抖动 // 生产可替换为 jsoniter + SortMapKeys 或 canonical JSON 库 b, err := json.Marshal(v) return string(b), err
} func BuildSnapshotBody(in SnapshotInput) (string, string, error) { payload := map[string]any{ "spu_id": in.SPU.SPUID, "sku_id": in.SKU.SKUID, "title": in.SPU.Title, "specs": in.SKU.SpecValues, "attrs": in.AttrDisplay, "images": in.SPU.MainImages, // 注意：可不包含实时价，避免与计价域重复；或仅保存 list_price 作为展示参考 } body, err := stableJSON(payload) if err != nil { return "", "", err } sum := sha256.Sum256([]byte(body)) hash := hex.EncodeToString(sum[:]) return body, hash, nil
} func FindOrCreateSnapshot(ctx context.Context, repo SnapshotRepository, in SnapshotInput) (*ProductSnapshot, error) { body, hash, err := BuildSnapshotBody(in) if err != nil { return nil, err } if snap, _ := repo.GetByID(ctx, hash); snap != nil { return snap, nil } snap := &ProductSnapshot{ SnapshotID: hash, SPUID: in.SPU.SPUID, SKUID: in.SKU.SKUID, BodyJSON: body, ContentHash: hash, CreatedAt: time.Now().UnixMilli(), } if err := repo.InsertIgnoreDuplicate(ctx, snap); err != nil { // 并发下可能命中唯一键冲突，回读即可 if isUniqueViolation(err) { return repo.GetByID(ctx, hash) } return nil, err } return snap, nil
}

