下表将常见品类映射到 (ManagementType, UnitType)，并给出推荐扣减时机（业务可配置）。 品类 管理类型 单元类型 推荐扣减时机 电子券 Deal Self Code 下单预占 OPV / 本地服务 Self Quantity 下单预占 酒店 Supplier Time 支付 / 供应商确认（按合同） 机票 Supplier Quantity / Time 支付前后组合（按供应商能力） 话费 TopUp Unlimited - 无库存扣减 礼品卡（预采购） Self Code 下单预占 礼品卡（实时生成） Supplier Code 支付后生成 组合套餐 Self Bundle 下单预占（子项联动） 下面的 四象限矩阵图 用「平台是否掌握库存事实来源」与「库存单元是否强结构化」两个视角，把常见品类放到同一张图里讨论（示意，用于工作坊对齐；边界案例以合同与供应商能力为准）。 flowchart TB subgraph Q1[象限 I：平台强主权 + 结构化数量/码池] Q1a[自管理 + 数量制：OPV / 本地服务] Q1b[自管理 + 券码制：Deal / 预采购礼品卡] end subgraph Q2[象限 II：平台强主权 + 组合复杂度] Q2a[自管理 + 组合型：套餐（子 SKU 联动）] end subgraph Q3[象限 III：供应商主权 + 时间/座位视图] Q3a[供应商 + 时间维度：酒店日历房态] Q3b[供应商 + 数量/座位：机票 / 部分票务] end subgraph Q4[象限 IV：弱库存约束 / 特殊模式] Q4a[无限库存：话费等直充] Q4b[供应商 + 券码实时生成：支付后出码] end MT[维度一：ManagementType] --> Q1 MT --> Q2 MT --> Q3 MT --> Q4 UT[维度二：UnitType] --> Q1 UT --> Q2 UT --> Q3 UT --> Q4 与营销库存的关系 ：商品库存回答「有没有货」，营销库存回答「活动名额 / 补贴预算够不够」。秒杀等场景往往需要 双扣减 （商品 + 营销），本章在 8.7 节说明集成边界；营销细节见第 9 章。 统一数据模型（持久化层摘要） ：二维分类解决「策略选择」，持久化层解决「数据落在哪里」。实践中常用三张核心表承载配置、数量视图与券码池（字段可按团队规范微调，但语义建议保持一致）。 inventory_config（按 SKU 一条） ：声明 management_type、unit_type、deduct_timing、supplier_id、sync_strategy 等，是策略路由的唯一配置源。 inventory（数量 / 时间维度的聚合行） ：维护 total/available/booking/locked/sold 与供应商快照字段（如 supplier_stock），并承载库存恒等式校验。 inventory_code_pool_XX（券码制分表） ：一码一行，状态机驱动；Redis LIST 仅存 codeId 热数据，权威仍在 MySQL。 CREATE TABLE inventory_config ( id BIGINT PRIMARY KEY AUTO_INCREMENT, item_id BIGINT NOT NULL, sku_id BIGINT NOT NULL DEFAULT 0, management_type INT NOT NULL COMMENT '1=自管理,2=供应商,3=无限', unit_type INT NOT NULL COMMENT '1=券码,2=数量,3=时间,4=组合', deduct_timing INT NOT NULL DEFAULT 1 COMMENT '1=下单,2=支付,3=发货', supplier_id BIGINT NOT NULL DEFAULT 0, sync_strategy INT NOT NULL DEFAULT 0 COMMENT '1=定时,2=实时,3=推送', sync_interval INT NOT NULL DEFAULT 300, oversell_allowed TINYINT NOT NULL DEFAULT 0, low_stock_threshold INT NOT NULL DEFAULT 100, UNIQUE KEY uk_item_sku (item_id, sku_id)
); CREATE TABLE inventory ( id BIGINT PRIMARY KEY AUTO_INCREMENT, item_id BIGINT NOT NULL, sku_id BIGINT NOT NULL, batch_id BIGINT NOT NULL DEFAULT 0, calendar_date DATE DEFAULT NULL, total_stock INT NOT NULL DEFAULT 0, available_stock INT NOT NULL DEFAULT 0, booking_stock INT NOT NULL DEFAULT 0, locked_stock INT NOT NULL DEFAULT 0, sold_stock INT NOT NULL DEFAULT 0, supplier_stock INT NOT NULL DEFAULT 0, supplier_sync_time BIGINT NOT NULL DEFAULT 0, status INT NOT NULL DEFAULT 1, UNIQUE KEY uk_sku_batch_date (sku_id, batch_id, calendar_date)
); 库存恒等式（自管理） ： total_stock = available_stock + booking_stock + locked_stock + sold_stock 可售库存的计算要分管理类型 ：自管理用平台 total/sold/booking/locked；供应商管理应用 supplier_stock 作为外部事实输入；无限库存返回业务定义的上限或哨兵值。把这段逻辑收敛在领域服务 CalcAvailable 中，避免在订单、搜索、结算各自复制一份。

26.body:
让我们通过一个具体的代码示例来理解 Clean Architecture 的价值。 反例：依赖具体实现 // ❌ 反例：OrderService 直接依赖具体的 MySQL 实现
package service import ( "database/sql" _ "github.com/go-sql-driver/mysql"
) type OrderService struct { db *sql.DB // 直接依赖 MySQL
} func (s *OrderService) CreateOrder(ctx context.Context, req CreateOrderReq) (*Order, error) { // 业务逻辑和数据库操作混在一起 tx, err := s.db.BeginTx(ctx, nil) if err != nil { return nil, err } defer tx.Rollback() order := &Order{ CustomerID: req.CustomerID, Items: req.Items, Total: calculateTotal(req.Items), } // SQL 语句直接写在业务逻辑中 _, err = tx.ExecContext(ctx, "INSERT INTO orders (customer_id, total, status) VALUES (?, ?, ?)", order.CustomerID, order.Total, "pending") if err != nil { return nil, err } return order, tx.Commit()
} 问题 ： 业务逻辑和数据库操作混在一起，难以测试 换数据库（如 PostgreSQL）需要改动业务逻辑代码 无法编写不依赖数据库的单元测试 OrderService 直接依赖 database/sql 和 MySQL 驱动 正例：依赖抽象 // ✅ 正例：Clean Architecture 方式 // domain/order/repository.go — 内层只定义接口
package order type Repository interface { Save(ctx context.Context, order *Order) error FindByID(ctx context.Context, id string) (*Order, error)
} // domain/order/order.go — 领域模型
package order type Order struct { id string customerID string items []OrderItem status Status totalPrice Money
} func NewOrder(customerID string) *Order { return &Order{ id: generateID(), customerID: customerID, items: make([]OrderItem, 0), status: StatusDraft, }
} func (o *Order) AddItem(product Product, qty int) error { if o.status != StatusDraft { return ErrOrderNotEditable } if qty <= 0 { return ErrInvalidQuantity } item := NewOrderItem(product, qty) o.items = append(o.items, item) o.recalculateTotal() return nil
} func (o *Order) Place() error { if len(o.items) == 0 { return ErrEmptyOrder } o.status = StatusPlaced return nil
} // usecase/place_order.go — Use Case 依赖接口而非实现
package usecase import "myapp/domain/order" type PlaceOrderUseCase struct { orderRepo order.Repository // 依赖抽象接口
} func (uc *PlaceOrderUseCase) Execute(ctx context.Context, req PlaceOrderRequest) (*PlaceOrderResponse, error) { // 创建订单聚合 o := order.NewOrder(req.CustomerID) // 添加商品 for _, item := range req.Items { product := order.Product{ID: item.ProductID, Price: item.Price} if err := o.AddItem(product, item.Quantity); err != nil { return nil, err } } // 下单 if err := o.Place(); err != nil { return nil, err } // 持久化（通过接口） if err := uc.orderRepo.Save(ctx, o); err != nil { return nil, err } return &PlaceOrderResponse{OrderID: o.ID()}, nil
} // adapter/persistence/mysql_order_repo.go — 外层实现接口
package persistence import ( "database/sql" "myapp/domain/order"
) type MySQLOrderRepo struct { db *sql.DB
} func NewMySQLOrderRepo(db *sql.DB) order.Repository { return &MySQLOrderRepo{db: db}
} func (r *MySQLOrderRepo) Save(ctx context.Context, o *order.Order) error { _, err := r.db.ExecContext(ctx, "INSERT INTO orders (id, customer_id, total, status) VALUES (?, ?, ?, ?)", o.ID(), o.CustomerID(), o.Total().Amount, o.Status().String()) return err
} func (r *MySQLOrderRepo) FindByID(ctx context.Context, id string) (*order.Order, error) { // 实现查询逻辑 // ... return nil, nil
} // adapter/persistence/mongo_order_repo.go — 换存储只需新增实现
package persistence import ( "go.mongodb.org/mongo-driver/mongo" "myapp/domain/order"
) type MongoOrderRepo struct { collection *mongo.Collection
} func NewMongoOrderRepo(col *mongo.Collection) order.Repository { return &MongoOrderRepo{collection: col}
} func (r *MongoOrderRepo) Save(ctx context.Context, o *order.Order) error { _, err := r.collection.InsertOne(ctx, bson.M{ "_id": o.ID(), "customer_id": o.CustomerID(), "total": o.Total().Amount, "status": o.Status().String(), }) return err
} 对比收益 ： 维度 反例（依赖具体实现） 正例（依赖抽象） 测试 必须启动 MySQL 才能测试 用 Mock 实现接口即可测试 换存储 改动业务逻辑代码 只需新增一个 Adapter 理解成本 业务逻辑和技术细节混在一起 业务逻辑清晰独立 并行开发 数据库schema确定后才能开发 定义好接口就可以并行开发

