在 Clean Architecture 中， 组装 （将接口与实现绑定）发生在最外层——通常是 main.go 或 cmd/server/main.go。 方式一：手动注入（推荐，适合中小项目） // cmd/server/main.go
package main import ( "database/sql" "log" "myapp/adapter/inbound/http" "myapp/adapter/outbound/persistence" "myapp/infra/mysql" "myapp/usecase" _ "github.com/go-sql-driver/mysql" "github.com/gin-gonic/gin"
) func main() { // 1. Infrastructure 层：初始化基础设施 db, err := sql.Open("mysql", "user:pass@tcp(localhost:3306)/mydb") if err != nil { log.Fatal(err) } defer db.Close() // 2. Adapter 层：创建实现（实现 domain 接口） orderRepo := persistence.NewMySQLOrderRepo(db) productRepo := persistence.NewMySQLProductRepo(db) // 3. Use Case 层：注入依赖 placeOrderUC := usecase.NewPlaceOrderUseCase(orderRepo, productRepo) cancelOrderUC := usecase.NewCancelOrderUseCase(orderRepo) // 4. Adapter 层（Inbound）：创建 HTTP Handler orderHandler := http.NewOrderHandler(placeOrderUC, cancelOrderUC) // 5. Framework 层：启动 Web 服务器 router := gin.Default() orderHandler.RegisterRoutes(router) router.Run(":8080")
} 优点 ： 零依赖，不需要引入任何 DI 框架 编译时检查，类型安全 调试直观，依赖关系一目了然 缺点 ： 当依赖超过 20 个时，main.go 变得冗长 手动管理依赖顺序，容易出错 方式二：Wire（适合大型项目） Google 的 Wire 通过代码生成实现依赖注入： // cmd/server/wire.go
//go:build wireinject package main import ( "myapp/adapter/inbound/http" "myapp/adapter/outbound/persistence" "myapp/infra/mysql" "myapp/usecase" "github.com/google/wire"
) func InitializeOrderHandler() (*http.OrderHandler, error) { wire.Build( // Infrastructure mysql.NewConnection, // Adapters (Outbound) persistence.NewMySQLOrderRepo, persistence.NewMySQLProductRepo, // Use Cases usecase.NewPlaceOrderUseCase, usecase.NewCancelOrderUseCase, // Adapters (Inbound) http.NewOrderHandler, ) return nil, nil
} 运行 wire ./cmd/server 后，Wire 会自动生成 wire_gen.go： // Code generated by Wire. DO NOT EDIT. func InitializeOrderHandler() (*http.OrderHandler, error) { db, err := mysql.NewConnection() if err != nil { return nil, err } orderRepo := persistence.NewMySQLOrderRepo(db) productRepo := persistence.NewMySQLProductRepo(db) placeOrderUC := usecase.NewPlaceOrderUseCase(orderRepo, productRepo) cancelOrderUC := usecase.NewCancelOrderUseCase(orderRepo) handler := http.NewOrderHandler(placeOrderUC, cancelOrderUC) return handler, nil
} 优点 ： 自动处理依赖顺序 编译时检查，类型安全 适合大型项目（100+ 依赖） 缺点 ： 需要学习 Wire 的 API 代码生成可能影响调试体验 方式三：Uber Fx（运行时注入） // cmd/server/main.go
package main import ( "go.uber.org/fx" "myapp/adapter/inbound/http" "myapp/adapter/outbound/persistence" "myapp/infra/mysql" "myapp/usecase"
) func main() { fx.New( // Infrastructure fx.Provide(mysql.NewConnection), // Adapters fx.Provide(persistence.NewMySQLOrderRepo), fx.Provide(persistence.NewMySQLProductRepo), // Use Cases fx.Provide(usecase.NewPlaceOrderUseCase), fx.Provide(usecase.NewCancelOrderUseCase), // HTTP Handler fx.Provide(http.NewOrderHandler), // Start server fx.Invoke(func(h *http.OrderHandler) { router := gin.Default() h.RegisterRoutes(router) router.Run(":8080") }), ).Run()
} 优点 ： 支持生命周期管理（启动/关闭钩子） 支持依赖图可视化 适合微服务框架 缺点 ： 运行时注入，类型错误要到运行时才能发现 学习曲线较陡 推荐选择 ： 小型项目（<50 个依赖） ：手动注入 中型项目（50-200 个依赖） ：Wire 大型项目（200+ 个依赖，微服务） ：Fx

