对账目标不是「每时每刻 Redis == MySQL」，而是 尽快发现破坏恒等式与异常漂移，并可控修复 。 建议对账维度： 单行恒等式 ：total = available + booking + locked + sold（字段含义以你的表结构为准）。 跨存储视图 ：Redis available vs MySQL available_stock 差值。 订单侧一致性 ：PENDING_PAYMENT 订单是否仍存在预占记录；是否出现「仅商品预占成功、营销失败」等半截状态。 flowchart TD A[定时对账任务启动] --> B[拉取自管理 SKU 配置] B --> C[读取 Redis 聚合视图] C --> D[读取 MySQL 权威行] D --> E{恒等式成立?} E -->|否| X[告警 + 冻结售卖 + 记缺陷单] E -->|是| F{Redis vs MySQL 差值超阈?} F -->|否| Z[记录健康指标] F -->|是| G{允许自动修复?} G -->|是| H[以 MySQL 为准重写 Redis] G -->|否| Y[仅告警 + 人工确认] H --> Z 修复策略要谨慎 ：自动以 MySQL 覆盖 Redis 适合「Redis 丢数据」类问题；若根因是重复消费导致 MySQL 多减，则应阻断自动修复，先定位消息幂等缺陷。 对账任务的伪代码骨架（Go） ：对账不仅是数值 diff，更是「缺陷驱动」的运营工具。下面示例强调阈值、恒等式与人工门闩（auto_reconcile）。为便于阅读，abs / max 等函数省略实现。 // 伪代码骨架：abs/max/alert/rewrite 需按项目工具库实现
func ReconcileItem(ctx context.Context, cfg InventoryConfig) error { redisAvail := readRedisAvailable(ctx, cfg.ItemID, cfg.SKUID) mysqlRow, err := loadInventoryRow(ctx, cfg.ItemID, cfg.SKUID) if err != nil { return err } if !mysqlRow.identityOK() { return fmt.Errorf("mysql identity broken: item=%d sku=%d", cfg.ItemID, cfg.SKUID) } diff := redisAvail - mysqlRow.AvailableStock if abs(diff) > max(100, mysqlRow.AvailableStock/10) { alert(ctx, "large inventory diff", cfg.ItemID, cfg.SKUID, diff) } if cfg.AutoReconcile { return rewriteRedisFromMySQL(ctx, cfg.ItemID, cfg.SKUID, mysqlRow) } return nil
}

