在实际项目中，Clean Architecture 的违规往往不是故意的，而是在时间压力下"顺手"写下的。以下是三个最常见的反模式： Anti-pattern 1：跨层调用 // ❌ 反例：Handler 直接引用了 MySQL 包（跳过了 domain 和 usecase 层）
package handler import ( "database/sql" "net/http"
) func GetOrder(db *sql.DB) http.HandlerFunc { return func(w http.ResponseWriter, r *http.Request) { row := db.QueryRow("SELECT * FROM orders WHERE id = ?", r.URL.Query().Get("id")) // 直接在 handler 里写 SQL... }
} 问题 ： Handler 直接依赖数据库，无法测试 业务逻辑散落在各个 Handler 中，无法复用 换数据库需要改动所有 Handler // ✅ 正例：Handler 只依赖 Use Case 接口
package handler type OrderQuerier interface { GetOrderDetail(ctx context.Context, id string) (*OrderDetailDTO, error)
} type OrderHandler struct { querier OrderQuerier
} func NewOrderHandler(q OrderQuerier) *OrderHandler { return &OrderHandler{querier: q}
} func (h *OrderHandler) GetOrder(w http.ResponseWriter, r *http.Request) { dto, err := h.querier.GetOrderDetail(r.Context(), r.URL.Query().Get("id")) if err != nil { http.Error(w, err.Error(), http.StatusInternalServerError) return } json.NewEncoder(w).Encode(dto)
} Anti-pattern 2：基础设施泄漏到领域层 // ❌ 反例：领域实体中使用了 sql.NullString（基础设施类型侵入领域）
package domain import "database/sql" type Order struct { ID string Remark sql.NullString // ← 领域层不应该知道 SQL 的存在 Status int // ← 用魔数表示状态
} 问题 ： sql.NullString 是 database/sql 包的类型，领域层不应该依赖基础设施包 领域模型变得"贫血"，只是数据容器，没有行为 // ✅ 正例：领域层使用纯 Go 类型，转换在 adapter 层完成
package domain type Order struct { id OrderID // 强类型 ID remark string // 空字符串表示无备注 status OrderStatus // 枚举类型，不是魔数 items []OrderItem
} func (o *Order) UpdateRemark(remark string) error { if len(remark) > 500 { return ErrRemarkTooLong } o.remark = remark return nil
} // adapter/persistence/converter.go — 在 Adapter 层做类型转换
func toDomain(po *OrderPO) *domain.Order { remark := "" if po.Remark.Valid { remark = po.Remark.String } status := domain.StatusFromInt(po.Status) return domain.ReconstructOrder( domain.OrderID(po.ID), remark, status, toItemList(po.Items), )
} func toPO(o *domain.Order) *OrderPO { return &OrderPO{ ID: string(o.ID()), Remark: sql.NullString{String: o.Remark(), Valid: o.Remark() != ""}, Status: o.Status().ToInt(), }
} Anti-pattern 3：循环依赖 ❌ domain/order.go imports adapter/notification adapter/notification imports domain/order → 编译失败：import cycle 问题 ： Go 不允许循环依赖，编译直接报错 即使在允许循环依赖的语言（如 C#），也会导致模块耦合 解法 ：在 domain 层定义 Notifier 接口，adapter 层实现它。方向始终 向内 。 // domain/notifier.go — 领域层定义接口
package domain type Notifier interface { NotifyOrderPlaced(ctx context.Context, order *Order) error
} // usecase/place_order.go — Use Case 依赖接口
type PlaceOrderUseCase struct { orderRepo order.Repository notifier domain.Notifier // 依赖抽象
} func (uc *PlaceOrderUseCase) Execute(ctx context.Context, req PlaceOrderRequest) error { // ... 创建订单 ... if err := uc.orderRepo.Save(ctx, o); err != nil { return err } // 通过接口调用通知 return uc.notifier.NotifyOrderPlaced(ctx, o)
} // adapter/notification/sms_notifier.go — Adapter 层实现接口
package notification type SMSNotifier struct { smsClient *SMSClient
} func (n *SMSNotifier) NotifyOrderPlaced(ctx context.Context, order *domain.Order) error { message := fmt.Sprintf("您的订单 %s 已创建", order.ID()) return n.smsClient.Send(ctx, order.CustomerPhone(), message)
} 依赖方向 ： domain (定义 Notifier 接口) ↑
usecase (依赖 Notifier 接口) ↑
adapter/notification (实现 Notifier 接口)

