模型拆分 ： Coupon（券批次） ：描述面额/折扣、门槛、总库存、每用户限领、适用范围（全场/类目/SKU）、承担方（平台/商家）。 CouponUser（用户券实例） ：领取时间、过期时间、状态（未使用/冻结/已使用/作废）。 CouponLog（审计流水） ：谁在何时以何因做了何动作；是对账与客服判责依据。 关键实现约束 ： 超发控制 ：热点券批次用 Redis 原子扣减「可领库存」，DB 落库作为最终事实；二者通过异步对账修正（见 9.8.2）。 核销一致性 ：下单冻结、支付成功确认核销、关单回滚；状态迁移必须落在 单用户券粒度锁 或等价乐观锁上，避免并发双花。 券批次生命周期与运营协同 ：除技术状态外，建议为运营提供「紧急下线」与「仅禁止新领取、已领取仍可用」两种模式。前者用于舆情与合规风险，后者用于预算将尽时的平滑收口。两种模式在网关与试算引擎侧都要有显式开关，避免只改数据库导致缓存层继续发券。 import ( "context" "strconv" "time"
) // CouponUserStatus 描述用户券生命周期（示意）
type CouponUserStatus string const ( CouponUserUnused CouponUserStatus = "UNUSED" CouponUserFrozen CouponUserStatus = "FROZEN" CouponUserUsed CouponUserStatus = "USED" CouponUserExpired CouponUserStatus = "EXPIRED"
) type FreezeCouponCommand struct { UserID int64 CouponUserID int64 OrderID int64 Idempotency string
} type CouponAppService struct { repo CouponRepository locker DistributedLock bus EventBus
} func (s *CouponAppService) Freeze(ctx context.Context, cmd FreezeCouponCommand) error { unlock, err := s.locker.Lock(ctx, "coupon_user:"+strconv.FormatInt(cmd.CouponUserID, 10), 3*time.Second) if err != nil { return err } defer unlock() cu, err := s.repo.GetCouponUserForUpdate(ctx, cmd.CouponUserID) if err != nil { return err } if cu.UserID != cmd.UserID { return ErrNotOwner } // 幂等：同一订单重复冻结直接成功 if cu.Status == CouponUserFrozen && cu.FrozenOrderID != nil && *cu.FrozenOrderID == cmd.OrderID { return nil } if cu.Status != CouponUserUnused { return ErrInvalidState } return s.repo.Transition(ctx, cmd.CouponUserID, Transition{ From: CouponUserUnused, To: CouponUserFrozen, OrderID: cmd.OrderID, Reason: "freeze_for_order", IdemKey: cmd.Idempotency, })
}

