账户模型 ：available / frozen 双桶； 流水 追加不可变； 过期 建议「批次/桶」或「到期索引表」驱动，避免全表扫描。 并发更新 ：高冲突账户使用 version 乐观重试；低冲突可用单行 CAS。对外接口必须支持 业务幂等键 （例如 biz_type + biz_id）防止重复发放。 import ( "context" "strconv" "time"
) type SpendPointsCommand struct { UserID int64 Points int64 OrderID int64 Idempotency string
} func (s *PointsAppService) Spend(ctx context.Context, cmd SpendPointsCommand) error { if ok, err := s.repo.InsertIdempotency(ctx, "points_spend", cmd.Idempotency); err != nil { return err } else if !ok { return nil } for i := 0; i < 5; i++ { acct, err := s.repo.GetAccount(ctx, cmd.UserID) if err != nil { return err } if acct.Available < cmd.Points { return ErrInsufficientPoints } affected, err := s.repo.UpdateAvailableCAS(ctx, cmd.UserID, acct.Version, acct.Available-cmd.Points, acct.TotalSpent+cmd.Points) if err != nil { return err } if affected == 1 { _ = s.repo.AppendLog(ctx, PointsLog{ UserID: cmd.UserID, Type: "SPEND", Delta: -cmd.Points, BizType: "ORDER", BizID: strconv.FormatInt(cmd.OrderID, 10), }) return nil } time.Sleep(time.Duration(10*(i+1)) * time.Millisecond) } return ErrWriteConflict
}

