补贴与「券/活动」不同之处在于： 它往往不直接以用户可见凭证表达 ，而是以 平台/商家承担比例 进入清结算。典型场景： 平台秒杀补贴：活动价低于供货价差额由平台承担。 联合营销：商家出资 70%，平台出资 30%。 支付立减：渠道补贴 + 平台补贴叠加（需风控与预算）。 数据落点 ：订单行级记录「营销成本分摊字段」；支付成功后由营销结算服务生成 结算事实表 ，推送给财务/对账系统（与 9.7.5 呼应）。 type SubsidySplit struct { OrderID int64 LineID int64 PlatformCent int64 MerchantCent int64 ThirdPartyCent int64 Currency string
} func mulDiv64(a, b, denom int64) int64 { if denom == 0 { return 0 } return (a * b) / denom
} func BuildSubsidySplit(line LinePriceSnapshot, policy CostSharePolicy) SubsidySplit { discount := line.ListCent - line.PayableCent platform := mulDiv64(discount, policy.PlatformBP, 10_000) third := mulDiv64(discount, policy.ChannelBP, 10_000) merchant := discount - platform - third if merchant < 0 { merchant = 0 } return SubsidySplit{OrderID: line.OrderID, LineID: line.LineID, PlatformCent: platform, MerchantCent: merchant, ThirdPartyCent: third, Currency: line.Currency}
}

