状态机要落地为 可执行的规则表 ，并显式区分三类约束： 结构约束 ：状态图允许的边（非法迁移直接拒绝）。 业务前置条件 ：例如上线要求 price > 0、available_stock > 0、类目必填、敏感字段已审核。 权限约束 ：商家能否从 OFFLINE 自恢复 ONLINE，通常取决于平台模式（POP 与自营差异极大）。 迁移 前置条件（示例） 典型操作者 DRAFT → PENDING 必填字段完整、图片合规 商家 / 运营 PENDING → APPROVED 审核通过 审核员 / 系统(自动) APPROVED → PUBLISHED 基础价已落库、关键属性锁定 系统编排 PUBLISHED → ONLINE 库存初始化成功、索引可用(可降级为异步) 系统编排 ONLINE → OFFLINE 无强约束 / 或存在风控拦截 运营 / 系统(库存0) * → ARCHIVED 无未完成订单、无未结算争议(按业务) 运营 权限与职责矩阵（落地提示） 生命周期状态迁移不仅要「技术上可执行」，还要能回答审计问题： 谁在什么证据下推动了状态变化 。建议将权限检查拆为两层： 领域权限 ：角色是否允许触发该边（例如商家通常不允许从 APPROVED 直跳 ONLINE）。 数据范围权限 ：运营仅能操作其负责类目；供应商账号仅能操作绑定 supplier_id 的映射商品。 对于系统自动迁移（例如库存为 0 触发 ONLINE → OFFLINE），必须在状态日志中记录 operator_type=SYSTEM 与触发规则编号，避免被误解为「后台偷偷改数据」。 与「变更审批」的关系澄清 主数据生命周期状态（DRAFT/.../ONLINE）与「字段级变更审批单」是两条正交维度：商品可以长期处于 ONLINE，但某个高价差改价仍可能处于 pending_approval。工程上不要让 item.status 承担所有流程语义，否则报表、搜索与交易链路会对状态产生错误假设。 Go：状态机骨架（结构约束 + 前置条件 + 乐观锁） package lifecycle import ( "context" "errors" "fmt" "time"
) type ItemStatus string const ( StatusDraft ItemStatus = "DRAFT" StatusPending ItemStatus = "PENDING" StatusRejected ItemStatus = "REJECTED" StatusApproved ItemStatus = "APPROVED" StatusPublished ItemStatus = "PUBLISHED" StatusOnline ItemStatus = "ONLINE" StatusOffline ItemStatus = "OFFLINE" StatusArchived ItemStatus = "ARCHIVED"
) type Item struct { ItemID int64 Status ItemStatus Version int64 Title string CategoryID int64 BasePrice int64 Stock int64
} type ItemRepository interface { GetByID(ctx context.Context, itemID int64) (*Item, error) UpdateStatusCAS(ctx context.Context, itemID int64, from, to ItemStatus, expectedVersion int64, now time.Time) (int64, error)
} type Preconditions interface { Check(ctx context.Context, item *Item, to ItemStatus) error
} type StateMachine struct { repo ItemRepository precond Preconditions
} func NewStateMachine(repo ItemRepository, pre Preconditions) *StateMachine { return &StateMachine{repo: repo, precond: pre}
} func (sm *StateMachine) CanTransition(from, to ItemStatus) bool { allowed := map[ItemStatus][]ItemStatus{ StatusDraft: {StatusPending, StatusArchived}, StatusPending: {StatusApproved, StatusRejected}, StatusRejected: {StatusDraft, StatusArchived}, StatusApproved: {StatusPublished}, StatusPublished: {StatusOnline}, StatusOnline: {StatusOffline, StatusArchived}, StatusOffline: {StatusOnline, StatusArchived}, } nexts, ok := allowed[from] if !ok { return false } for _, s := range nexts { if s == to { return true } } return false
} func (sm *StateMachine) Transition(ctx context.Context, itemID int64, to ItemStatus) error { for attempt := 0; attempt < 3; attempt++ { item, err := sm.repo.GetByID(ctx, itemID) if err != nil { return err } if !sm.CanTransition(item.Status, to) { return fmt.Errorf("invalid transition: %s -> %s", item.Status, to) } if err := sm.precond.Check(ctx, item, to); err != nil { return err } rows, err := sm.repo.UpdateStatusCAS(ctx, itemID, item.Status, to, item.Version, time.Now()) if err != nil { return err } if rows == 1 { return nil } // version conflict: retry } return errors.New("concurrent update: exceeded retries")
}

