上架的长耗时环节包括：图片转码、敏感词检测、类目预测、价格合规校验、写索引。API 层应 快速受理 ，把重活交给异步 Worker，并通过 Webhook / 轮询接口返回进度。 flowchart LR API[Listing API] --> Q[(队列 / 延迟队列)] API --> DB[(任务库)] Q --> W1[校验 Worker] Q --> W2[审核编排 Worker] Q --> W3[供给编排 Worker] W3 --> PC[商品中心写入] W3 --> INV[库存初始化] W3 --> PRC[计价初始化] W3 --> ES[搜索索引构建] W2 --> APQ[审核队列] APQ --> W2 PC --> OB[(Outbox)] OB --> BUS[Kafka] Go：受理请求（落库 + 投递 + 幂等键） package listing import ( "context" "crypto/sha256" "encoding/hex" "fmt" "time"
) type CreateListingCommand struct { IdempotencyKey string OperatorID int64 CategoryID int64 PayloadJSON []byte
} type ListingTask struct { TaskID int64 TaskCode string Status string CreatedAt time.Time
} type Store interface { InsertTaskIfAbsent(ctx context.Context, t *ListingTask) (inserted bool, err error) EnqueueValidateJob(ctx context.Context, taskID int64) error
} type Service struct { store Store clock func() time.Time
} func taskCodeFrom(cmd CreateListingCommand, now time.Time) string { h := sha256.Sum256([]byte(fmt.Sprintf("%s|%d|%d|%d", cmd.IdempotencyKey, cmd.OperatorID, cmd.CategoryID, now.UnixNano()))) return hex.EncodeToString(h[:12])
} func (s *Service) CreateTask(ctx context.Context, cmd CreateListingCommand) (*ListingTask, bool, error) { now := s.clock() task := &ListingTask{ TaskCode: taskCodeFrom(cmd, now), Status: "CREATED", CreatedAt: now, } inserted, err := s.store.InsertTaskIfAbsent(ctx, task) if err != nil { return nil, false, err } if !inserted { // 返回已有任务：幂等语义 return task, false, nil } if err := s.store.EnqueueValidateJob(ctx, task.TaskID); err != nil { return task, true, err } return task, true, nil
}

