当供应商同步与运营编辑并发时，推荐默认策略： 人工运营变更优先于供应商自动同步 （在「内容类字段」上）。 供应商在「库存/可售状态」上优先 （更接近真实供给）。 价格字段 ：可用「时间戳新者胜出 + 风险阈值审核」组合，避免运营锁价被无意覆盖。 字段级「锁」与合并策略（平台治理常见需求） 运营有时会明确标注「标题不允许供应商覆盖」「主图允许供应商更新」。实现上建议在商品主数据或扩展表中维护 field_locks（bitmap 或 JSON），同步管线在 diff 之后执行 merge_policy： LOCKED_BY_OPS：供应商变更到达时跳过该字段，并记录审计日志（不是静默吞掉，而是可查询）。 MERGE_IF_NEWER：比较 external_updated_at 与本地 supplier_projection.updated_at。 ALWAYS_REVIEW：字段变更永远生成审批单（适合品牌、类目、合规属性）。 Upsert 处理流程（含审核分支） flowchart TD A[接收供应商变更] --> K{幂等键已处理?} K -->|是| Z[ACK 返回重复] K -->|否| B{按 external_id 查找 item} B -->|不存在| C[创建 item + 映射 external_id] B -->|存在| D[计算字段 diff] C --> E{新创建是否需要审核?} E -->|是| F[创建审批单] E -->|否| G[落库 + 发布事件] D --> H{RiskEngine 路由} H -->|NONE| G H -->|AUTO| I{自动规则通过?} I -->|是| G I -->|否| F H -->|MANUAL/STRICT| F F --> J[等待人工/多级审核] J -->|通过| G J -->|驳回| R[记录原因 + 同步失败指标] G --> S[更新 supplier_sync_state] Go：Upsert 入口（展示分支，不含具体 ORM） package supplier import ( "context" "errors" "fmt"
) type ExternalItem struct { ExternalID string Title string PriceCent int64 Stock int64
} type ItemRepository interface { FindBySupplierExternal(ctx context.Context, supplierID int64, externalID string) (*Item, error) CreateFromExternal(ctx context.Context, supplierID int64, ext *ExternalItem) (*Item, error)
} type RiskRouter interface { Route(ctx context.Context, item *Item, ext *ExternalItem) (Strategy, error)
} type Strategy string const ( StrategyNone Strategy = "NONE" StrategyAuto Strategy = "AUTO" StrategyManual Strategy = "MANUAL"
) type SyncService struct { items ItemRepository risk RiskRouter
} type Item struct { ItemID int64 SupplierID int64 ExternalID string
} func (s *SyncService) Upsert(ctx context.Context, supplierID int64, ext *ExternalItem) error { if ext.ExternalID == "" { return errors.New("external_id required") } item, err := s.items.FindBySupplierExternal(ctx, supplierID, ext.ExternalID) if errors.Is(err, ErrNotFound) { _, err := s.items.CreateFromExternal(ctx, supplierID, ext) return err } if err != nil { return err } strategy, err := s.risk.Route(ctx, item, ext) if err != nil { return err } switch strategy { case StrategyNone: return s.applyDirect(ctx, item, ext) case StrategyAuto: return s.applyAuto(ctx, item, ext) case StrategyManual: return s.enqueueApproval(ctx, item, ext) default: return fmt.Errorf("unknown strategy: %s", strategy) }
} var ErrNotFound = errors.New("not found") func (s *SyncService) applyDirect(ctx context.Context, item *Item, ext *ExternalItem) error { // TODO: txn + outbox + downstream projections return nil
} func (s *SyncService) applyAuto(ctx context.Context, item *Item, ext *ExternalItem) error { return nil } func (s *SyncService) enqueueApproval(ctx context.Context, item *Item, ext *ExternalItem) error { return nil
}

