DDD 的战术设计关注的是代码层面的实现：如何用聚合、实体、值对象等战术模式编写高质量的领域模型。 战术设计概述 概念 定义 示例 Aggregate（聚合） 一组相关对象的集合，确保数据的一致性边界 Order 聚合包含 OrderItem 列表 Aggregate Root（聚合根） 聚合的入口对象，外部只能通过它访问聚合 Order 是聚合根，OrderItem 不能被单独访问 Entity（实体） 有唯一标识的对象，按 ID 区分 User（不同 ID = 不同用户） Value Object（值对象） 没有唯一标识，仅由属性定义 Money(100, "USD")、Address Domain Event（领域事件） 领域中发生的有意义的事实 OrderPlaced、PaymentCompleted Domain Service（领域服务） 不属于任何实体的业务逻辑 跨聚合的转账操作 Go 代码示例：Order 聚合 // domain/order/order.go
package order import ( "errors" "time"
) type OrderID string type Order struct { id OrderID customerID string items []OrderItem status OrderStatus totalPrice Money createdAt time.Time
} // 聚合根通过方法保护业务不变量
func (o *Order) AddItem(product Product, qty int) error { // 业务规则 1：只有草稿状态的订单才能添加商品 if o.status != OrderStatusDraft { return ErrOrderNotEditable } // 业务规则 2：数量必须大于 0 if qty <= 0 { return ErrInvalidQuantity } // 业务规则 3：同一商品不能重复添加（或合并数量） for i, item := range o.items { if item.ProductID == product.ID { o.items[i].Quantity += qty o.recalculateTotal() return nil } } item := NewOrderItem(product, qty) o.items = append(o.items, item) o.recalculateTotal() return nil
} func (o *Order) Place() ([]DomainEvent, error) { // 业务规则 4：订单必须至少有一个商品 if len(o.items) == 0 { return nil, ErrEmptyOrder } // 业务规则 5：只有草稿状态才能下单 if o.status != OrderStatusDraft { return nil, ErrInvalidOrderStatus } o.status = OrderStatusPlaced // 发布领域事件 events := []DomainEvent{ OrderPlacedEvent{ OrderID: o.id, Total: o.totalPrice, At: time.Now(), }, } return events, nil
} func (o *Order) recalculateTotal() { total := Money{Amount: 0, Currency: "USD"} for _, item := range o.items { itemTotal, _ := item.Price.Multiply(item.Quantity) total, _ = total.Add(itemTotal) } o.totalPrice = total
} // Getters（聚合根控制外部访问）
func (o *Order) ID() OrderID { return o.id }
func (o *Order) CustomerID() string { return o.customerID }
func (o *Order) Status() OrderStatus { return o.status }
func (o *Order) Total() Money { return o.totalPrice } // domain/order/money.go — Value Object（值对象）
package order import "errors" type Money struct { Amount int64 // 使用分为单位，避免浮点精度问题 Currency string
} func (m Money) Add(other Money) (Money, error) { if m.Currency != other.Currency { return Money{}, ErrCurrencyMismatch } return Money{ Amount: m.Amount + other.Amount, Currency: m.Currency, }, nil
} func (m Money) Multiply(factor int) (Money, error) { if factor < 0 { return Money{}, errors.New("factor must be positive") } return Money{ Amount: m.Amount * int64(factor), Currency: m.Currency, }, nil
} func (m Money) String() string { return fmt.Sprintf("%d.%02d %s", m.Amount/100, m.Amount%100, m.Currency)
} 关键设计要点 ： 业务规则内聚 ：所有的业务规则都在聚合根的方法中，而不是散落在 Service 层 不变量保护 ：聚合根保证内部数据的一致性（如 totalPrice 始终是 items 的总和） 领域事件 ：聚合根发生重要状态变化时，返回领域事件 值对象 ：Money 是值对象，保证金额计算的精度和货币一致性

