func (s *InventoryService) LockStock(ctx context.Context, skuID string, qty int) error { stock, err := s.stockRepo.FindBySKU(ctx, skuID) if err != nil { return err } // 业务术语：锁定库存 if err := stock.Lock(qty); err != nil { return err } return s.stockRepo.Save(ctx, stock)
} // domain/inventory/stock.go
func (s *Stock) Lock(qty int) error { if s.available < qty { return ErrInsufficientStock } s.available -= qty s.locked += qty return nil
} 对比 ： ❌ updateInventoryStatus(orderId, status=2) — 技术术语，无业务含义 ✅ stock.Lock(qty) — 业务术语，直接表达意图

