聚合设计是 DDD 战术层面最难的部分。三条核心原则： 原则一：一个事务只修改一个聚合 // ❌ 反例：一个事务同时修改 Order 和 Inventory 两个聚合
func (s *OrderService) PlaceOrder(ctx context.Context, cmd PlaceOrderCmd) error { return s.txManager.RunInTx(ctx, func(tx *sql.Tx) error { order := domain.NewOrder(cmd.CustomerID) order.AddItem(cmd.ProductID, cmd.Qty) order.Place() s.orderRepo.SaveTx(tx, order) // 修改 Order 聚合 s.inventoryRepo.DeductTx(tx, cmd.ProductID, cmd.Qty) // ← 同时修改 Inventory 聚合 return nil })
} 问题 ： 两个聚合在同一个事务中修改，导致锁粒度过大 Order 和 Inventory 强耦合，无法独立演进 高并发场景下容易死锁 // ✅ 正例：通过领域事件实现跨聚合协作
func (s *OrderService) PlaceOrder(ctx context.Context, cmd PlaceOrderCmd) error { order := domain.NewOrder(cmd.CustomerID) order.AddItem(cmd.ProductID, cmd.Qty) events, err := order.Place() if err != nil { return err } // 只保存 Order 聚合 if err := s.orderRepo.Save(ctx, order); err != nil { return err } // 发布事件，由 Inventory 服务异步消费 s.eventBus.Publish(ctx, events...) return nil
} // inventory 服务的事件处理器
func (h *InventoryEventHandler) OnOrderPlaced(ctx context.Context, e OrderPlacedEvent) error { return h.stock.Deduct(ctx, e.ProductID, e.Qty)
} 收益 ： Order 和 Inventory 解耦，可以独立扩展 事务范围缩小，提高并发性能 通过事件实现最终一致性 原则二：小聚合优于大聚合 维度 小聚合 大聚合 并发冲突 低（锁粒度小） 高（整个大聚合被锁） 内存占用 小（按需加载） 大（整棵树一次加载） 一致性范围 单个核心不变量 多个不变量混在一起 适用场景 高并发写入 强一致性要求的小规模数据 判断标准 ：如果两个实体之间没有需要在同一个事务中保护的 业务不变量 ，就应该拆成两个聚合。 示例 ： // ❌ 大聚合：Order 聚合包含 Customer 的完整信息
type Order struct { id OrderID customer *Customer // 包含 Customer 的所有信息 items []OrderItem
} // 问题：加载 Order 时被迫加载 Customer 的所有信息（地址、订单历史等） // ✅ 小聚合：Order 只保存 CustomerID
type Order struct { id OrderID customerID CustomerID // 只存 ID，需要时按需查询 items []OrderItem
} // 需要 Customer 信息时，通过 Repository 查询
func (uc *OrderDetailUseCase) GetOrderDetail(ctx context.Context, orderID string) (*OrderDetailDTO, error) { order, err := uc.orderRepo.FindByID(ctx, orderID) if err != nil { return nil, err } customer, err := uc.customerRepo.FindByID(ctx, order.CustomerID()) if err != nil { return nil, err } return &OrderDetailDTO{ OrderID: string(order.ID()), CustomerName: customer.Name(), Items: order.Items(), }, nil
} 原则三：通过 ID 引用其他聚合 // ❌ 聚合内直接持有另一个聚合的引用
type Order struct { customer *Customer // 直接引用 → 加载 Order 时被迫加载 Customer
} // ✅ 通过 ID 引用
type Order struct { customerID CustomerID // 只存 ID，需要时按需查询
} 收益 ： 聚合边界清晰，加载 Order 不会加载 Customer 聚合之间松耦合，可以独立演进 减少内存占用和数据库 JOIN

