Repository 是领域模型和持久化之间的桥梁，它提供了 类似集合的接口 来访问聚合。 标准 Repository 模式 // domain/order/repository.go — 领域层定义接口
package order type Repository interface { Save(ctx context.Context, order *Order) error FindByID(ctx context.Context, id OrderID) (*Order, error) FindByCustomerID(ctx context.Context, customerID string, limit int) ([]*Order, error)
} Repository 的职责 ： 提供类似集合的接口（Save, FindByID, Remove） 隐藏底层存储细节（MySQL/MongoDB/Redis） 保证聚合的完整加载和保存 Unit of Work 模式 标准 Repository 每个操作独立，但有时需要在一个事务中协调多个 Repository（例如保存聚合根 + 写 Outbox 表）。Unit of Work 模式解决这个问题： // domain/uow.go — 领域层定义接口
package domain type UnitOfWork interface { OrderRepo() order.Repository OutboxRepo() OutboxRepository Commit(ctx context.Context) error Rollback(ctx context.Context) error
} // infrastructure/uow_impl.go — 基础设施层实现
package infrastructure type mysqlUnitOfWork struct { tx *sql.Tx orderRepo *MySQLOrderRepo outboxRepo *MySQLOutboxRepo
} func NewUnitOfWork(db *sql.DB) (domain.UnitOfWork, error) { tx, err := db.Begin() if err != nil { return nil, err } return &mysqlUnitOfWork{ tx: tx, orderRepo: &MySQLOrderRepo{tx: tx}, outboxRepo: &MySQLOutboxRepo{tx: tx}, }, nil
} func (u *mysqlUnitOfWork) OrderRepo() order.Repository { return u.orderRepo }
func (u *mysqlUnitOfWork) OutboxRepo() OutboxRepository { return u.outboxRepo }
func (u *mysqlUnitOfWork) Commit(ctx context.Context) error { return u.tx.Commit() }
func (u *mysqlUnitOfWork) Rollback(ctx context.Context) error { return u.tx.Rollback() } // application/command/place_order.go — Use Case 使用 UoW
func (h *PlaceOrderHandler) Handle(ctx context.Context, cmd PlaceOrderCmd) error { uow, err := h.uowFactory(ctx) if err != nil { return err } defer uow.Rollback(ctx) order := domain.NewOrder(cmd.CustomerID) events, err := order.Place() if err != nil { return err } // 同一个事务中保存聚合和 Outbox if err := uow.OrderRepo().Save(ctx, order); err != nil { return err } for _, e := range events { if err := uow.OutboxRepo().Save(ctx, toOutboxEntry(e)); err != nil { return err } } return uow.Commit(ctx)
}

