端到端时序：从「编排完成」到「用户可感知」 下图强调两个事实：其一，商品中心仍是主数据写入枢纽；其二，搜索/缓存等读模型是 异步最终一致 ，因此「商品已 ONLINE」与「用户可搜到」之间存在可度量时间窗，应用监控覆盖该窗口，而不是假设同步完成。 sequenceDiagram participant ORCH as 供给编排器 participant PC as 商品中心 participant INV as 库存系统 participant PRC as 计价系统 participant OB as Outbox Dispatcher participant BUS as Kafka participant ES as 搜索索引 participant CDN as 缓存失效 ORCH->>PC: UpsertItemCommand（事务内） ORCH->>INV: InitStock / Adjust（按场景） ORCH->>PRC: InitBasePrice（按场景） PC->>OB: 写入 outbox（同事务） ORCH-->>ORCH: 提交事务 OB->>BUS: 发布 product.* 事件 BUS->>ES: 消费建索引/更新 BUS->>CDN: 消费删缓存键 flowchart LR subgraph write_path[写入路径] ORCH[编排器] --> PC[(商品中心)] ORCH --> INV[(库存)] ORCH --> PRC[(计价)] PC --> OB[(Outbox)] end OB --> BUS[Kafka / MQ] BUS --> C1[搜索消费者] BUS --> C2[推荐消费者] BUS --> C3[缓存失效消费者] BUS --> C4[营销投影消费者] C1 --> ES[(ES 索引)] C3 --> RD[(Redis)] 消费者幂等 要点： 以 event_id 做 Redis SETNX 或 DB 唯一表去重 处理逻辑尽量 可重放 （replay）而非依赖「刚好一次」网络 package integration import ( "context" "errors"
) type Consumer interface { Handle(ctx context.Context, evt Event) error
} type Event struct { EventID string Type string ItemID int64
} type Deduper interface { Seen(ctx context.Context, eventID string) (bool, error) Mark(ctx context.Context, eventID string) error
} type IdempotentConsumer struct { inner Consumer deduper Deduper
} func (c IdempotentConsumer) Handle(ctx context.Context, evt Event) error { seen, err := c.deduper.Seen(ctx, evt.EventID) if err != nil { return err } if seen { return nil } if err := c.inner.Handle(ctx, evt); err != nil { return err } if err := c.deduper.Mark(ctx, evt.EventID); err != nil { return err } return nil
} var ErrRetry = errors.New("retryable failure")

