现象 ：索引延迟升高，搜索空窗扩大 直接原因 ：批量导入与实时变更共用同一 consumer group 根因 ：缺少队列隔离与背压 修复 ：拆分 topic / group，导入走独立链路 预防 ：容量基线与灰度开关纳入发布检查清单 案例 B：供应商重复推送导致「幽灵改价」 某供应商在网关超时后重试回调，平台侧未做 message_id 去重，导致短时间内价格被回滚到旧值，又触发自动审核通过，最终造成活动价与展示价不一致。 修复点 ：Push 入口落「去重表 + 业务版本号」；应用变更前比较 external_version。 预防点 ：把供应商重试策略纳入联调验收清单（超时、重试间隔、幂等键）。 案例 C：乐观锁重试风暴 大促期间运营批量改标题，与搜索 Hydrate 触发的轻量回写并发，导致大量 version conflict，worker 无限重试放大 DB 压力。 修复点 ：批量任务改为分片串行 per item；读路径回写避免触碰高频 version 字段。 预防点 ：区分「内容字段版本」与「展示投影版本」，避免所有变更都 bump 同一 version。 Go：基于版本号的并发写（带退避） package concurrency import ( "context" "errors" "time"
) var ErrConflict = errors.New("version conflict") type ItemWriter interface { Load(ctx context.Context, itemID int64) (price int64, version int64, err error) CASUpdatePrice(ctx context.Context, itemID int64, newPrice int64, fromVersion int64) (rows int64, err error)
} func UpdatePriceWithRetry(ctx context.Context, w ItemWriter, itemID int64, newPrice int64) error { var last error for i := 0; i < 5; i++ { _, ver, err := w.Load(ctx, itemID) if err != nil { return err } n, err := w.CASUpdatePrice(ctx, itemID, newPrice, ver) if err != nil { last = err } else if n == 1 { return nil } else { last = ErrConflict } time.Sleep(time.Duration(10*(i+1)) * time.Millisecond) } return last
}

