批量场景用 errgroup 并发拉取多 SKU 基础价与活动； 热点 SKU 预热 ； 对 Layer 内 RPC 设置 独立超时与熔断 ，避免一层拖垮整条链。 package pricing import ( "context" "sync" "time"
) type CacheManager struct { mu sync.Mutex l1 map[string]cacheEntry l1TTL time.Duration
} type cacheEntry struct { val *PricingResponse expiresAt time.Time
} func NewCacheManager(l1TTL time.Duration) *CacheManager { return &CacheManager{l1: make(map[string]cacheEntry), l1TTL: l1TTL}
} func (c *CacheManager) GetOrCompute(ctx context.Context, key string, fn func(context.Context) (*PricingResponse, error)) (*PricingResponse, error) { now := time.Now() c.mu.Lock() if e, ok := c.l1[key]; ok && now.Before(e.expiresAt) { c.mu.Unlock() return e.val, nil } c.mu.Unlock() val, err := fn(ctx) if err != nil { return nil, err } c.mu.Lock() c.l1[key] = cacheEntry{val: val, expiresAt: now.Add(c.l1TTL)} c.mu.Unlock() return val, nil
} 生产环境可在 L1 之上再接 Redis、并接入 singleflight；此处展示「先读内存、未命中再计算回写」的最小闭环。

