以 订单行 / 购物车行 为粒度定义聚合根 Price（本书与实现中可与 PricingAggregate 等价命名），保证： 同一行上 互斥营销 的选择规则在一个聚合内完成； 行小计 与 层明细 同步更新； 对外只暴露 已完成校验 的结果。 package domain import "errors" type LayerKind int const ( LayerBase LayerKind = iota LayerPromotion LayerDeduction LayerCharge
) // Price 聚合根：表示「一行 SKU 在一次请求下」的可报价过程。
type Price struct { lineID string skuID int64 quantity int64 layers []PriceLayer ctx PricingContext version int64
} func NewPrice(lineID string, skuID, qty int64, ctx PricingContext) (*Price, error) { if qty <= 0 { return nil, errors.New("quantity must be positive") } return &Price{lineID: lineID, skuID: skuID, quantity: qty, ctx: ctx}, nil
} func (p *Price) ReplaceLayer(kind LayerKind, delta Money, meta map[string]string) error { if delta.IsNegative() && kind == LayerBase { return errors.New("base layer cannot go negative") } // 同类层覆盖或追加策略由领域规则决定，此处示意「按 kind 幂等替换」 p.layers = upsertLayer(p.layers, kind, delta, meta) return nil
} func upsertLayer(existing []PriceLayer, kind LayerKind, delta Money, meta map[string]string) []PriceLayer { nl := make([]PriceLayer, 0, len(existing)+1) replaced := false for _, l := range existing { if l.Kind == kind { nl = append(nl, PriceLayer{Kind: kind, Delta: delta, Meta: cloneMeta(meta)}) replaced = true continue } nl = append(nl, l) } if !replaced { nl = append(nl, PriceLayer{Kind: kind, Delta: delta, Meta: cloneMeta(meta)}) } return nl
} func cloneMeta(m map[string]string) map[string]string { if m == nil { return nil } out := make(map[string]string, len(m)) for k, v := range m { out[k] = v } return out
} func (p *Price) Subtotal() (Money, error) { var sum Money for _, l := range p.layers { var err error sum, err = sum.Add(l.Delta) if err != nil { return Money{}, err } } return sum, nil
} 聚合边界 ：Price 内不直接修改「券库存」「活动预算」——这些属于营销聚合，由应用服务先 预留 / 锁定 后再传入 Price 已选结果。 若团队纠结「一行 SKU 是否太小」：可以从 一致性边界 反推——任何「必须在同一事务里决定且一起成功或失败」的价格要素，应处于同一聚合；若某些营销是平台级自动领取、失败可静默降级，则不必纳入 Price 聚合，而可作为 Layer 2 的只读输入。购物车多行场景下， 行级 Price 聚合 + 订单级领域服务 是常见组合：行内互斥活动放在行聚合，跨行满减分摊放在服务。

