当逻辑 跨多行 或 不适合放入单一 Price 时，使用领域服务，例如： 订单级满减分摊 ：余额递减法处理尾差； 互斥活动择优 ：跨多个候选活动比较用户实付； Bundle 计价 ：买 N 享 M 折等。 package domain import "errors" // LineAmount 表示一行在分摊前的可参与金额（通常为 Layer1+2+4 之后的行小计，单位：分）。
type LineAmount struct { LineID string Cents int64
} // ApportionmentService：订单级优惠按行权重分摊（余额递减 + 尾差落末行）。
type ApportionmentService struct{} func (ApportionmentService) Allocate(orderDiscountCents int64, lines []LineAmount) ([]int64, error) { if orderDiscountCents < 0 { return nil, errors.New("discount must be non-negative") } if len(lines) == 0 { return nil, errors.New("no lines") } var total int64 for _, l := range lines { if l.Cents < 0 { return nil, errors.New("line amount cannot be negative") } total += l.Cents } if total == 0 { return nil, errors.New("total weight is zero") } out := make([]int64, len(lines)) var allocated int64 for i := 0; i < len(lines)-1; i++ { // 按比例向下取整到分 part := orderDiscountCents * lines[i].Cents / total out[i] = part allocated += part } out[len(lines)-1] = orderDiscountCents - allocated return out, nil
} 领域服务 无状态 ，入参出参均为领域对象或值对象。

