package command type PlaceOrderCommand struct { CustomerID string Items []OrderItemDTO
} type CommandResult struct { Success bool ID string Error error
} type PlaceOrderHandler struct { orderRepo order.Repository eventBus EventBus
} func (h *PlaceOrderHandler) Handle(ctx context.Context, cmd PlaceOrderCommand) CommandResult { order := domain.NewOrder(cmd.CustomerID) for _, item := range cmd.Items { if err := order.AddItem(item.ProductID, item.Qty); err != nil { return CommandResult{Error: err} } } events, err := order.Place() if err != nil { return CommandResult{Error: err} } if err := h.orderRepo.Save(ctx, order); err != nil { return CommandResult{Error: err} } h.eventBus.Publish(ctx, events...) return CommandResult{Success: true, ID: string(order.ID())}
