对外推荐 单一主叙事 ： 导购查询服务（Merchandising Query Service） 暴露统一查询接口，用 scene 区分业务语义；内部共享 Query → Recall → Rank → Hydrate 流水线。网关可做鉴权、限流与字段裁剪，但 不要把排序规则散落在多个 BFF 中。 scene 用户输入 典型 filter 召回主索引 keyword 关键词 + 可选类目 / 品牌 上架可售、合规、店铺黑名单 全站商品索引（或按站点分片） category 无关键词或空 query 固定 category_id + 同上 同上 shop 可选关键词 固定 shop_id + 同上 店铺子索引或单索引强 filter 店铺维度实现二选一： 独立索引别名 （写入侧按 shop 路由，查询简单）或 单索引 + 强 filter （运维简单，超大店需关注分片热点）。scene 应进入 日志、追踪与实验分桶 ，与 query_id、rank_version 一并贯穿。 // Scene 为导购域的稳定枚举，避免魔法字符串散落。
type Scene string const ( SceneKeyword Scene = "keyword" SceneCategory Scene = "category" SceneShop Scene = "shop"
) type UnifiedQuery struct { Scene Scene SiteID string UserID string // 可选，用于会员价 Hydrate RawQuery string // keyword 场景必填；category 可空 CategoryID string ShopID string Filters []Filter // 品牌、价格带、属性等 Page PageCursor ExpID string RankVersion string
} func RouteScene(req UnifiedQuery) (Scene, error) { if req.Scene != "" { return req.Scene, nil } switch { case req.ShopID != "": return SceneShop, nil case req.CategoryID != "" && strings.TrimSpace(req.RawQuery) == "": return SceneCategory, nil case strings.TrimSpace(req.RawQuery) != "": return SceneKeyword, nil default: return "", errors.New("unable to route scene: missing query/category/shop") }
}

