编排（Orchestration） 负责：scene 路由 → Query 理解 → 构建 ES DSL → 执行召回 → 粗精重排 → 触发 Hydrate → 合并 DTO。编排层应保持 无业务状态的纯函数倾向 ：依赖通过接口注入，核心流水线可单测。 type MerchandisingQueryService struct { QU QueryUnderstanding ES SearchClient Rank Ranker Hydr Hydrator CFG OpConfigClient
} func (s *MerchandisingQueryService) Search(ctx context.Context, req UnifiedQuery) (*SearchResult, error) { scene, err := RouteScene(req) if err != nil { return nil, err } qctx, err := s.QU.Normalize(ctx, scene, req) if err != nil { return nil, err } recall, err := s.ES.Recall(ctx, qctx) if err != nil { return nil, err } ranked := s.Rank.Score(ctx, req, recall) reranked := s.Rank.Rerank(ctx, req, ranked, s.CFG) // 运营配置、打散、强插 cards, err := s.Hydr.Hydrate(ctx, HydrateRequest{ Scene: scene, UserID: req.UserID, DocIDs: reranked.IDs(), RankVersion: req.RankVersion, }) if err != nil { // Hydrate 全局失败应极少：通常部分降级 return nil, err } return AssembleResult(reranked, cards), nil
} 演进注记：何时拆 BFF 。当「列表卡片组装」与「搜索实验」发布节奏被不同团队强绑定时，常见折中是把 Hydrate 后的视图组装 下沉到 BFF，但 排序分数、实验桶、rank_version 仍应由导购查询内核产出并透传。否则会出现「实验只在 App 搜索生效、H5 列表不生效」的割裂，排查时日志还对不齐。另一个反模式是把 ES DSL 拼接散落在多个网关插件里：短期看似减少了一次 RPC，长期 DSL 变更无法回归测试， 零结果率 波动也无法定位是改写问题还是索引问题。 编排层还应内置 最小可观测上下文 ：query_id 应在进入 QU.Normalize 之前生成，并注入到 ES 查询注解（如 preference / custom header）与下游 RPC metadata 中，保证一次用户请求能在日志系统里 串起全链路 。若你们使用 OpenTelemetry，建议把 scene、rank_version、exp_id 作为 span attributes，而不是塞进自由文本日志。

