列表卡片常需： 展示价、原价划线、库存状态、营销标、店铺名 。变化快于索引刷新时，必须由 Hydrate 补齐。 契约建议 ：入参 doc_ids[]（上限如 50）、user_id（可选）、scene、rank_version；出参为 map[id]CardEnrichment，缺失键表示单卡失败。 Hydrate 编排 强调：批量、限时、可降级、可观测。下图描述 并行依赖 与 超时隔离 （示意）： flowchart LR subgraph Req["HydrateRequest"] IDS[doc_ids 上限 N] end subgraph Orch["编排器 Hydrator"] SPL[拆分批次/限流] EG[errgroup 并发池] MERGE[合并 map 结果] DEF[缺省策略/占位] end subgraph Deps["下游只读依赖"] A[计价批量] B[库存摘要批量] C[营销标签批量] D[商品读批量] end IDS --> SPL --> EG EG --> A EG --> B EG --> C EG --> D A --> MERGE B --> MERGE C --> MERGE D --> MERGE MERGE --> DEF type CardEnrichment struct { ListPriceCents *int64 // 展示价（分）；nil 表示 Hydrate 未取到 StrikePriceCents *int64 // 划线价（分） StockLevel string // 如 IN_STOCK / LOW / UNKNOWN PromoTags []string Title string MainImageURL string
} type HydrateRequest struct { Scene Scene UserID string SiteID string DocIDs []int64 RankVersion string
} type Hydrator struct { Pricing PricingBatchClient Inv InventoryBatchClient Mkt MarketingBatchClient Product ProductBatchClient Parallel int PerDep time.Duration
} func (h *Hydrator) Hydrate(ctx context.Context, req HydrateRequest) (map[int64]CardEnrichment, error) { g, ctx := errgroup.WithContext(ctx) if h.Parallel > 0 { g.SetLimit(h.Parallel) } out := sync.Map{} // map[int64]CardEnrichment run := func(fn func(context.Context) map[int64]CardEnrichment) { g.Go(func() error { cctx, cancel := context.WithTimeout(ctx, h.PerDep) defer cancel() partial := fn(cctx) for id, card := range partial { v, _ := out.LoadOrStore(id, CardEnrichment{}) base := v.(CardEnrichment) out.Store(id, mergeCard(base, card)) } return nil // 单依赖失败不失败整页：在 fn 内部吞错 }) } run(func(c context.Context) map[int64]CardEnrichment { m, _ := h.Pricing.BatchListPrices(c, req.SiteID, req.UserID, req.DocIDs) return m }) run(func(c context.Context) map[int64]CardEnrichment { m, _ := h.Inv.BatchStockSummary(c, req.SiteID, req.DocIDs) return m }) run(func(c context.Context) map[int64]CardEnrichment { m, _ := h.Mkt.BatchPromoTags(c, req.SiteID, req.UserID, req.DocIDs) return m }) run(func(c context.Context) map[int64]CardEnrichment { m, _ := h.Product.BatchCardFields(c, req.SiteID, req.DocIDs) return m }) _ = g.Wait() merged := make(map[int64]CardEnrichment, len(req.DocIDs)) for _, id := range req.DocIDs { if v, ok := out.Load(id); ok { merged[id] = v.(CardEnrichment) } } return merged, nil
} func mergeCard(a, b CardEnrichment) CardEnrichment { // 教学示例：按字段非空合并 if b.ListPriceCents != nil { a.ListPriceCents = b.ListPriceCents } if b.StrikePriceCents != nil { a.StrikePriceCents = b.StrikePriceCents } if b.StockLevel != "" { a.StockLevel = b.StockLevel } if len(b.PromoTags) > 0 { a.PromoTags = append(a.PromoTags, b.PromoTags...) } if b.Title != "" { a.Title = b.Title } if b.MainImageURL != "" { a.MainImageURL = b.MainImageURL } return a
} Hydrate 与「列表一致性」 ：当某个 SPU 在 ES 中仍存在，但商品中心已下架或不可售时，应以 商品读返回的状态 为准做最终过滤，并在必要时 剔除该位 或 显示不可用 （取决于产品策略）。这意味着 Hydrate 不只是「加字段」，也可能反向改变 可展示集合 ；若发生剔除，需要在前端处理 页大小不足 的补位逻辑（例如自动补拉一条），否则会出现末尾空洞。 连接池与超时 ：Hydrate 依赖往往共享连接池，若列表 QPS 高且每页 50 条，极易把下游 最大并发 顶满。除了限制 Parallel 与批量大小，还应对 同一用户 做轻量节流（例如滑动窗口），防止脚本或异常客户端发起「并发多页请求」放大扇出。

