引入 CQRS 后，写模型和读模型之间存在 延迟 （通常毫秒到秒级）。这需要在架构层面和用户体验层面同时处理。 架构层面 策略一：幂等消费 投影器可能收到重复事件（at-least-once delivery），必须做幂等处理： func (p *OrderProjector) Project(ctx context.Context, event DomainEvent) error { // 幂等性检查：事件是否已处理 exists, err := p.readDB.EventProcessed(ctx, event.ID()) if err != nil { return err } if exists { return nil // 已处理过，跳过 } // 处理事件 switch e := event.(type) { case OrderPlacedEvent: dto := OrderDetailDTO{ OrderID: string(e.OrderID), Status: "placed", TotalPrice: e.Total.String(), CreatedAt: e.At.Format(time.RFC3339), } if err := p.readDB.Upsert(ctx, dto); err != nil { return err } } // 标记事件已处理 return p.readDB.MarkEventProcessed(ctx, event.ID())
} 策略二：补偿事务（Saga） 当跨服务操作中某一步失败，通过发布补偿事件回滚前面的步骤： 正向流程：CreateOrder → ReserveStock → ChargePayment
补偿流程： ReleaseStock ← RefundPayment ← PaymentFailed 我们会在 第6章 详细讲解 Saga 模式。 用户体验层面 Optimistic UI（乐观更新） ：前端在发送 Command 后立即更新 UI，不等待读模型同步。 用户点击"下单" → 前端立即显示"订单已创建"（乐观更新） → 后端 Command 异步处理 → 读模型延迟 200ms 后更新 → 用户下次刷新时看到真实状态 Read-your-writes ：Command 成功后返回版本号，Query 时带上版本号，确保读到的是自己写入之后的数据。 // Command 返回版本号
type CommandResult struct { Success bool ID string Version int64 // 版本号
} // Query 时带上版本号
type OrderDetailQuery struct { OrderID string MinVersion int64 // 期望读到的最小版本
} // Query Handler 检查版本
func (h *OrderDetailHandler) Handle(ctx context.Context, q OrderDetailQuery) (*OrderDetailDTO, error) { dto, err := h.readDB.FindOrderDetail(ctx, q.OrderID) if err != nil { return nil, err } // 如果读模型版本低于期望版本，返回错误或等待 if dto.Version < q.MinVersion { return nil, ErrReadModelNotReady } return dto, nil
}

