投影器是 CQRS 架构中将 领域事件 转化为 读模型 的组件。 flowchart LR A[Event Store / MQ] --> B[Projector] B --> C[(Read DB)] B --> D{事件类型路由} D -->|OrderPlaced| E[创建订单读模型] D -->|ItemAdded| F[更新商品明细] D -->|OrderCancelled| G[标记订单取消] 完整实现 // adapter/projection/projector.go
package projection type Projector interface { Handles() []string // 返回该 Projector 关心的事件类型列表 Project(ctx context.Context, event DomainEvent) error
} type OrderReadModelProjector struct { readDB ReadModelRepository
} func (p *OrderReadModelProjector) Handles() []string { return []string{"OrderPlaced", "OrderCancelled", "ItemAdded", "PaymentCompleted"}
} func (p *OrderReadModelProjector) Project(ctx context.Context, event DomainEvent) error { switch e := event.(type) { case OrderPlacedEvent: return p.readDB.Upsert(ctx, OrderReadModel{ OrderID: string(e.OrderID), Status: "placed", Total: e.Total.Amount, Currency: e.Total.Currency, CreatedAt: e.At, }) case OrderCancelledEvent: return p.readDB.UpdateStatus(ctx, string(e.OrderID), "cancelled") case PaymentCompletedEvent: return p.readDB.UpdateStatus(ctx, string(e.OrderID), "paid") default: return nil }
} 投影器的运行模式 模式 机制 延迟 适用场景 同步投影 Command Handler 执行完后同步调用 Projector 零延迟 读写在同一进程、低吞吐 异步投影 事件通过 MQ 传递，Projector 独立消费 毫秒~秒级 高吞吐、读写分离部署 Catch-up 投影 Projector 从事件存储按序号拉取事件 可控 重建读模型、新增投影视图 电商系统推荐 ： 异步投影 ，理由： 读写可以独立扩展（写用MySQL，读用ES） 故障隔离（读模型崩溃不影响写操作） 性能最优（异步处理不阻塞写操作）

