以一个电商"下单"请求为例，完整走一遍三件套协作的全链路。每一步标注所属的 架构层 和 概念 。 步骤 ① [Adapter 层 / Inbound] HTTP Handler 接收请求 // adapter/inbound/http/order_handler.go
package http import ( "myapp/application/command" "github.com/gin-gonic/gin"
) type OrderHandler struct { placeOrderHandler *command.PlaceOrderHandler
} func (h *OrderHandler) PlaceOrder(c *gin.Context) { var req PlaceOrderRequest if err := c.ShouldBindJSON(&req); err != nil { c.JSON(400, gin.H{"error": err.Error()}) return } // 转换为 Command（DTO → Command） cmd := command.PlaceOrderCommand{ CustomerID: req.CustomerID, Items: toCommandItems(req.Items), } result := h.placeOrderHandler.Handle(c.Request.Context(), cmd) if result.Error != nil { c.JSON(500, gin.H{"error": result.Error.Error()}) return } c.JSON(201, gin.H{"order_id": result.ID})
} 步骤 ② [Application 层 / CQRS Command Path] Command Handler 编排业务流程 // application/command/place_order.go
package command import ( "context" "myapp/domain" "myapp/domain/order"
) type PlaceOrderHandler struct { uowFactory func(context.Context) (domain.UnitOfWork, error) productReader ProductReader
} func (h *PlaceOrderHandler) Handle(ctx context.Context, cmd PlaceOrderCommand) CommandResult { // 创建 UoW（事务边界） uow, err := h.uowFactory(ctx) if err != nil { return CommandResult{Error: err} } defer uow.Rollback(ctx) // ③ [Domain 层 / DDD Aggregate] 操作聚合根 o := order.NewOrder(order.CustomerID(cmd.CustomerID)) for _, item := range cmd.Items { product, err := h.productReader.GetByID(ctx, item.ProductID) if err != nil { return CommandResult{Error: err} } if err := o.AddItem(product, item.Qty); err != nil { return CommandResult{Error: err} } } events, err := o.Place() // 聚合根返回领域事件 if err != nil { return CommandResult{Error: err} } // ④ [Adapter 层 / Outbound] 持久化聚合 + Outbox if err := uow.OrderRepo().Save(ctx, o); err != nil { return CommandResult{Error: err} } for _, e := range events { if err := uow.OutboxRepo().Save(ctx, toOutboxEntry(e)); err != nil { return CommandResult{Error: err} } } if err := uow.Commit(ctx); err != nil { return CommandResult{Error: err} } return CommandResult{Success: true, ID: string(o.ID())}
} 步骤 ⑤ [Adapter 层 / Projection] Outbox Relay 发送事件 → Projector 更新读模型 // adapter/projection/order_projector.go
package projection func (p *OrderProjector) Project(ctx context.Context, event DomainEvent) error { switch e := event.(type) { case domain.OrderPlacedEvent: return p.readDB.Upsert(ctx, ReadOrderModel{ OrderID: string(e.OrderID), CustomerName: p.customerName(ctx, e.CustomerID), Items: p.buildItemList(ctx, e.Items), TotalPrice: e.Total.String(), Status: "placed", CreatedAt: e.At, }) } return nil
} 步骤 ⑥ [Application 层 / CQRS Query Path] 读请求绕过领域模型 // application/query/order_detail.go
package query type OrderDetailHandler struct { readDB ReadModelRepository
} func (h *OrderDetailHandler) Handle(ctx context.Context, q OrderDetailQuery) (*OrderDetailDTO, error) { // 直接从读库返回 DTO，绕过领域模型 return h.readDB.FindByOrderID(ctx, q.OrderID)
} 全链路概览表 步骤 架构层 概念 代码位置 ① 接收 HTTP 请求 Adapter (Inbound) - handler/order_handler.go ② 编排业务流程 Application CQRS Command command/place_order.go ③ 操作聚合根 Domain DDD Aggregate domain/order/order.go ④ 持久化 + Outbox Adapter (Outbound) Outbox Pattern persistence/mysql_order_repo.go ⑤ 投影到读模型 Adapter (Projection) CQRS Projector projection/order_projector.go ⑥ 读请求直查 Application CQRS Query query/order_detail.go

