回调处理必须「 先验签、再幂等、再状态机推进、再副作用 」。副作用包括：写流水、记渠道交易号、插入 Outbox 事件。任何一步失败都要有 可重试 或 明确失败码 ，避免渠道端无限重试雪崩。 回调入口建议独立部署（甚至独立集群），与创单读多路径隔离，避免大促时查询流量挤占回调写路径。入口层完成 TLS、限流、IP 白名单后，应尽快把报文写入 原始回调表 （append-only），再异步处理——这样即使后续逻辑发布回滚，也不会丢凭证。 func firstHeader(headers map[string][]string, key string) string { v := headers[key] if len(v) == 0 { return "" } return v[0]
} func VerifyNotify(channel string, headers map[string][]string, body []byte, pubKey string) error { // 伪代码：不同 channel 选择不同验签算法与字段拼接顺序。 sig := firstHeader(headers, "X-Signature") if sig == "" { return fmt.Errorf("missing signature") } ok, err := verifyChannelSignature(channel, body, sig, pubKey) if err != nil { return err } if !ok { return fmt.Errorf("bad signature") } return nil
} func verifyChannelSignature(channel string, body []byte, sig string, pubKey string) (bool, error) { // 落地时在此处分发到各渠道验签实现。 return true, nil
}

