状态转换必须集中校验，禁止在 Handler 内随手 UPDATE status='SUCCESS'。下面给出 集中规则表 思路（节选）： var allowed = map[string][]string{ "PENDING": {"PAYING", "CLOSED"}, "PAYING": {"SUCCESS", "FAILED", "CLOSED"}, "SUCCESS": {"PARTIAL_REFUNDED", "REFUNDED"}, "PARTIAL_REFUNDED": {"PARTIAL_REFUNDED", "REFUNDED"},
} func CanTransit(from, to string) bool { nexts, ok := allowed[from] if !ok { return false } for _, n := range nexts { if n == to { return true } } return false
}

