退款单应独立建模，关联 payment_id 与 order_id，并具备自己的幂等键（如 order_id + refund_batch_no）。创建退款单时需要： 校验支付单处于可退状态； 校验退款权限（售后窗口、履约状态由订单域返回或事件驱动）； 锁定「可退余额」计算，防止并发双退。 并发双退的典型漏洞是「两次请求同时读到相同已退金额」。工程上可用 数据库行锁 （SELECT ... FOR UPDATE 锁支付单）或 原子 SQL （UPDATE payment SET refunded = refunded + ? WHERE id=? AND paid-refunded>=?）保证上限。若退款跨多个支付单（组合支付），要么在订单域生成 退款编排单 一次性下发，要么在支付域引入 分布式锁 / 事务消息 串行化。 // 以下为退款创建事务骨架：CreateRefundCmd / Refund / lockPaymentForRefund 由项目定义。
func (s *RefundService) CreateRefund(ctx context.Context, cmd CreateRefundCmd) (*Refund, error) { tx, err := s.db.BeginTx(ctx, nil) if err != nil { return nil, err } defer tx.Rollback() p, err := lockPaymentForRefund(ctx, tx, cmd.PaymentID) if err != nil { return nil, err } if p.Status != StatusSuccess && p.Status != StatusPartialRefunded { return nil, fmt.Errorf("payment not refundable") } refundable := p.PaidFen - p.RefundedFen if cmd.AmountFen <= 0 || cmd.AmountFen > refundable { return nil, fmt.Errorf("invalid refund amount") } r := NewRefund(cmd) if err := insertRefund(ctx, tx, r); err != nil { return nil, err } return r, tx.Commit()
}

