func (s *PaymentService) CreatePayment(ctx context.Context, orderID int64, amount int64) (*Payment, error) { payment := &Payment{ ID: generatePaymentID(), OrderID: orderID, Amount: amount, Status: PaymentStatusCreated, } s.repo.Save(ctx, payment) return payment, nil
} // Step 2: 调用支付渠道（支付宝/微信）
func (s *PaymentService) Pay(ctx context.Context, paymentID int64, channel string) (*PayURL, error) { gateway := s.gatewayFactory.Get(channel) payURL, err := gateway.CreateOrder(ctx, payment) return payURL, err
} // Step 3: 接收支付回调（幂等处理）
func (s *PaymentService) HandleCallback(ctx context.Context, callbackData *CallbackData) error { // 幂等性检查 payment, err := s.repo.GetByPaymentID(ctx, callbackData.PaymentID) if payment.Status == PaymentStatusPaid { return nil // 已处理，幂等返回 } // 验签 if !s.verifySign(callbackData) { return errors.New("签名验证失败") } // 更新支付状态（乐观锁） affected, err := s.repo.UpdateStatus(ctx, callbackData.PaymentID, PaymentStatusCreated, PaymentStatusPaid) if affected == 0 { return errors.New("支付单状态已变更") } // 发布支付成功事件 s.eventPublisher.Publish(ctx, &PaymentPaidEvent{ OrderID: payment.OrderID, PaymentID: payment.ID, Amount: payment.Amount, }) return nil
} 对账流程 ： // 每小时对账任务
func (s *PaymentService) ReconcileHourly(ctx context.Context, hour time.Time) error { // Step 1: 获取本地支付记录 localPayments, _ := s.repo.GetByHour(ctx, hour) // Step 2: 获取支付渠道对账单 remotePayments, _ := s.gatewayClient.DownloadBill(ctx, hour) // Step 3: 比对差异 diff := s.compare(localPayments, remotePayments) // Step 4: 处理差异 for _, d := range diff { if d.Type == Missing { // 本地有，渠道无 → 可能是渠道延迟 s.alertService.Alert("支付对账差异", d) } else if d.Type == Extra { // 本地无，渠道有 → 可能是回调丢失 s.补单处理(d) } } return nil
