供给运营是电商平台的核心能力 ，决定了"商品如何进入平台"。本节展示供给侧和运营侧的完整设计。 商品上架系统（从无到有） 业务场景 ： 运营人员手动上传新商品 商家通过Portal批量导入 Excel批量上架（节假日大促前） 核心设计 ： // 上架任务状态机
type ListingStatus string const ( ListingDraft ListingStatus = "DRAFT" // 草稿 ListingPending ListingStatus = "PENDING" // 待审核 ListingApproved ListingStatus = "APPROVED" // 审核通过 ListingRejected ListingStatus = "REJECTED" // 审核驳回 ListingPublished ListingStatus = "PUBLISHED" // 已发布
) // 上架任务
type ListingTask struct { TaskCode string // 幂等性标识 ItemInfo ItemInfo // 商品信息 SupplierID int64 // 供应商ID Status ListingStatus ReviewerID int64 // 审核人 RejectReason string // 驳回原因 CreatedAt time.Time UpdatedAt time.Time
} // 创建上架任务（幂等性保证）
func (s *ListingService) CreateListingTask(ctx context.Context, req *ListingRequest) (*ListingTask, error) { // Step 1: 生成幂等性标识符 taskCode := s.generateTaskCode(req) // Step 2: FirstOrCreate（幂等性） task := &ListingTask{ TaskCode: taskCode, ItemInfo: req.ItemInfo, SupplierID: req.SupplierID, Status: ListingDraft, } result := s.db.Where("task_code = ?", taskCode).FirstOrCreate(task) if result.RowsAffected > 0 { // 首次创建，发布事件 s.eventPublisher.Publish(ctx, &ListingTaskCreatedEvent{ TaskCode: taskCode, ItemInfo: req.ItemInfo, }) } return task, nil
} // 提交审核
func (s *ListingService) SubmitForReview(ctx context.Context, taskCode string) error { // 状态转换：DRAFT → PENDING return s.updateStatus(ctx, taskCode, ListingDraft, ListingPending)
} // 审核通过
func (s *ListingService) Approve(ctx context.Context, taskCode string, reviewerID int64) error { // Step 1: 状态转换：PENDING → APPROVED if err := s.updateStatus(ctx, taskCode, ListingPending, ListingApproved); err != nil { return err } // Step 2: 创建商品记录（写入商品中心） task, _ := s.getTask(ctx, taskCode) itemID, err := s.productCenter.CreateProduct(ctx, &CreateProductRequest{ ItemInfo: task.ItemInfo, SupplierID: task.SupplierID, }) if err != nil { return fmt.Errorf("create product failed: %w", err) } // Step 3: 初始化库存（调用库存服务） s.inventoryClient.InitStock(ctx, itemID, task.ItemInfo.InitStock) // Step 4: 初始化价格（调用计价服务） s.pricingClient.InitPrice(ctx, itemID, task.ItemInfo.BasePrice) // Step 5: 更新搜索索引（异步） s.eventPublisher.Publish(ctx, &ProductCreatedEvent{ ItemID: itemID, ItemInfo: task.ItemInfo, SupplierID: task.SupplierID, }) return nil
} 审核策略 ： 审核维度 检查项 风险等级 合规性 违禁词检测、敏感内容 高 完整性 必填字段、图片数量 中 准确性 价格合理性、类目匹配 中 一致性 SPU/SKU关系、属性匹配 低 供应商同步系统（Upsert场景） 业务场景 ： 供应商定时推送商品数据（每小时/每天） 供应商实时推送价格/库存变更 供应商商品可能已存在，也可能不存在 核心挑战 ：Upsert语义 如果商品存在 → 更新
如果商品不存在 → 创建 实现方案 ： // 供应商同步任务
type SyncTask struct { SyncID string // 同步批次ID SupplierID int64 // 供应商ID SupplierSkuID string // 供应商SKU ID SyncData SyncData // 同步数据 SyncType string // FULL/INCREMENTAL Status string // PENDING/SUCCESS/FAILED
} // Upsert处理（幂等性保证）
func (s *SyncService) UpsertProduct(ctx context.Context, req *SyncRequest) error { // Step 1: 根据供应商SKU ID查询平台商品ID mapping, err := s.repo.GetMapping(ctx, req.SupplierID, req.SupplierSkuID) if err == ErrNotFound { // 场景1：商品不存在 → 创建（走上架流程） return s.createNewProduct(ctx, req) } else { // 场景2：商品存在 → 更新（走同步流程） return s.updateExistingProduct(ctx, mapping.ItemID, req) }
} // 创建新商品（供应商同步触发的上架）
func (s *SyncService) createNewProduct(ctx context.Context, req *SyncRequest) error { // Step 1: 创建上架任务 task, err := s.listingService.CreateListingTask(ctx, &ListingRequest{ ItemInfo: transformToItemInfo(req.SyncData), SupplierID: req.SupplierID, Source: "SUPPLIER_SYNC", // 标记来源 }) // Step 2: 根据供应商信用等级，决定是否需要审核 if s.needReview(req.SupplierID) { // 低信用供应商：需要人工审核 task.Status = ListingPending } else { // 高信用供应商：自动通过 task.Status = ListingApproved s.listingService.Approve(ctx, task.TaskCode, SYSTEM_REVIEWER_ID) } return nil
} // 更新现有商品（供应商同步）
