type Order struct { // 聚合根ID orderID OrderID // 值对象 // 基本信息 userID int64 shopID int64 // 订单明细（实体集合） items []*OrderItem // 价格信息（值对象） pricing *OrderPricing // 状态（值对象） status OrderStatus // 时间戳 createdAt time.Time updatedAt time.Time // 领域事件（未提交） domainEvents []DomainEvent
} // 值对象：OrderID
type OrderID struct { value string
} func NewOrderID() OrderID { return OrderID{value: generateSnowflakeID()}
} func (id OrderID) String() string { return id.value
} // 值对象：OrderPricing
type OrderPricing struct { subtotal int64 // 商品总价 discount int64 // 折扣金额 couponDiscount int64 // 优惠券 payableAmount int64 // 应付金额
} func (p *OrderPricing) Calculate() int64 { return p.subtotal - p.discount - p.couponDiscount
} // 实体：OrderItem
type OrderItem struct { itemID int64 skuID int64 quantity int unitPrice int64 // 快照 snapshot *ItemSnapshot
} // 聚合根方法：状态转换
func (o *Order) TransitionTo(newStatus OrderStatus) error { // 检查状态转换是否合法 if !o.status.CanTransitionTo(newStatus) { return fmt.Errorf("不允许从 %s 转换到 %s", o.status, newStatus) } oldStatus := o.status o.status = newStatus o.updatedAt = time.Now() // 发布领域事件 o.addDomainEvent(&OrderStatusChangedEvent{ OrderID: o.orderID, OldStatus: oldStatus, NewStatus: newStatus, ChangedAt: o.updatedAt, }) return nil
} // 聚合根方法：添加商品项
func (o *Order) AddItem(item *OrderItem) error { // 不变量检查：订单金额不能超过限额 if o.calculateTotal()+item.Total() > MAX_ORDER_AMOUNT { return errors.New("订单金额超过限额") } o.items = append(o.items, item) // 发布领域事件 o.addDomainEvent(&OrderItemAddedEvent{ OrderID: o.orderID, Item: item, }) return nil
} // 不变量：订单金额 = 所有商品项之和
func (o *Order) calculateTotal() int64 { total := int64(0) for _, item := range o.items { total += item.Total() } return total
} // 领域事件管理
func (o *Order) addDomainEvent(event DomainEvent) { o.domainEvents = append(o.domainEvents, event)
} func (o *Order) DomainEvents() []DomainEvent { return o.domainEvents
} func (o *Order) ClearDomainEvents() { o.domainEvents = nil
}

