// Outbox表（确保事件必达）
type Outbox struct { ID int64 EventType string EventData string // JSON Status string // PENDING/PUBLISHED/FAILED RetryCount int CreatedAt time.Time
} // 发布领域事件（Outbox模式）
func (p *EventPublisher) Publish(ctx context.Context, event DomainEvent) error { // Step 1: 序列化事件 eventData, _ := json.Marshal(event) // Step 2: 写入Outbox表（与业务在同一事务） outbox := &Outbox{ EventType: event.Type(), EventData: string(eventData), Status: "PENDING", CreatedAt: time.Now(), } return p.db.Create(outbox).Error
} // Outbox轮询器（定时扫描未发布的事件）
func (w *OutboxWorker) Run() { ticker := time.NewTicker(1 * time.Second) defer ticker.Stop() for range ticker.C { // Step 1: 查询待发布事件（PENDING状态） var outboxes []*Outbox w.db.Where("status = ? AND retry_count < ?", "PENDING", 3). Limit(100). Find(&outboxes) // Step 2: 发布到Kafka for _, outbox := range outboxes { err := w.kafkaProducer.Send(outbox.EventType, outbox.EventData) if err == nil { // 发布成功，标记为PUBLISHED w.db.Model(outbox).Update("status", "PUBLISHED") } else { // 发布失败，重试计数+1 w.db.Model(outbox).Updates(map[string]interface{}{ "retry_count": gorm.Expr("retry_count + 1"), "status": "FAILED", }) } } }
}

