} func (s *CreateOrderSaga) Execute(ctx context.Context, req *CreateOrderRequest) (*Order, error) { var reserveID string var couponLockID string // Step 1: 库存预占 reserve, err := s.inventoryClient.ReserveStock(ctx, req.Items) if err != nil { return nil, fmt.Errorf("库存预占失败: %w", err) } reserveID = reserve.ReserveID defer func() { if err != nil { // 补偿：释放库存 s.inventoryClient.ReleaseStock(ctx, reserveID) } }() // Step 2: 优惠券锁定 couponLock, err := s.marketingClient.LockCoupon(ctx, req.CouponCode, req.UserID) if err != nil { return nil, fmt.Errorf("优惠券锁定失败: %w", err) } couponLockID = couponLock.LockID defer func() { if err != nil { // 补偿：释放优惠券 s.marketingClient.UnlockCoupon(ctx, couponLockID) } }() // Step 3: 创建订单 order := &Order{ ID: generateOrderID(), UserID: req.UserID, Items: req.Items, ReserveID: reserveID, CouponLockID: couponLockID, Status: StatusPendingPayment, } err = s.orderRepo.Save(ctx, order) if err != nil { return nil, fmt.Errorf("订单创建失败: %w", err) } return order, nil
}

