缓存策略 （多级缓存）： // L1: 本地缓存（进程内）
type LocalCache struct { cache *bigcache.BigCache
} func (c *LocalCache) Get(key string) (interface{}, error) { data, err := c.cache.Get(key) if err == nil { return unmarshal(data), nil } return nil, err
} // L2: Redis缓存
// L3: MySQL数据库 func (s *ProductService) GetProduct(ctx context.Context, skuID int64) (*Product, error) { // L1: 本地缓存 if product, err := s.localCache.Get(skuID); err == nil { return product, nil } // L2: Redis缓存 if product, err := s.redis.Get(ctx, fmt.Sprintf("product:%d", skuID)); err == nil { s.localCache.Set(skuID, product) // 回填L1 return product, nil } // L3: MySQL数据库 product, err := s.repo.GetByID(ctx, skuID) if err != nil { return nil, err } // 回填缓存 s.redis.Set(ctx, fmt.Sprintf("product:%d", skuID), product, 30*time.Minute) s.localCache.Set(skuID, product) return product, nil
} 批量查询优化 ： // 批量获取商品信息（减少RPC调用）
func (s *ProductService) BatchGetProducts(ctx context.Context, skuIDs []int64) (map[int64]*Product, error) { // Step 1: 尝试从缓存批量获取 cached := s.redis.MGet(ctx, toCacheKeys(skuIDs)) // Step 2: 找出缺失的ID missingIDs := findMissing(skuIDs, cached) // Step 3: 批量查询数据库（IN查询） if len(missingIDs) > 0 { missing, _ := s.repo.GetByIDs(ctx, missingIDs) // 回填缓存 s.redis.MSet(ctx, missing, 30*time.Minute) cached = merge(cached, missing) } return cached, nil
} 数据库优化 ： -- 索引优化
CREATE INDEX idx_order_user_create ON `order` (user_id, create_time DESC);
CREATE INDEX idx_order_status ON `order` (status, create_time DESC); -- 避免SELECT *（只查询需要的字段）
SELECT order_id, status, total_price FROM `order` WHERE user_id = ?; -- 分页优化（使用索引覆盖）
SELECT order_id FROM `order` WHERE user_id = ? AND create_time > ?
ORDER BY create_time DESC
LIMIT 20;

