灰度策略 ： // 灰度规则
type GrayReleaseRule struct { Version string // 新版本号 Percentage int // 流量比例（0-100） Whitelist []int64 // 白名单用户ID Regions []string // 灰度地区
} func (r *GrayRouter) Route(userID int64, region string) string { // 白名单用户直接路由到新版本 if contains(r.rule.Whitelist, userID) { return r.rule.Version } // 按地区灰度 if !contains(r.rule.Regions, region) { return "stable" // 老版本 } // 按百分比灰度 if hash(userID) % 100 < r.rule.Percentage { return r.rule.Version // 新版本 } return "stable" // 老版本
} 灰度步骤 ： 1. 5%流量（白名单用户 + 内部员工） 观察1小时：错误率、延迟、业务指标 2. 20%流量（特定地区） 观察2小时 3. 50%流量 观察4小时 4. 100%流量（全量发布） 观察24小时 5. 下线老版本

