防腐层把外部不稳定协议挡在边界之外，领域层只依赖自己的端口接口。 package order import ( "context" "fmt"
) type OrderID string // Money 表示订单上下文的应付金额（示例：用分存储，避免 float）。
type Money struct { cents int64 currency string
} func NewMoneyFromCents(cents int64, currency string) Money { return Money{cents: cents, currency: currency}
} func (m Money) DecimalYuan() string { if m.cents < 0 { return "0.00" } yuan := m.cents / 100 fen := m.cents % 100 return fmt.Sprintf("%d.%02d", yuan, fen)
} // PaymentSession 是领域侧对「可跳转支付」的最小抽象，不暴露渠道字段。
type PaymentSession struct { CheckoutURL string
} type StartPaymentCommand struct { OrderID OrderID Payable Money
} // PaymentGateway 由订单领域定义：表达「我需要的支付能力」，由基础设施实现。
type PaymentGateway interface { StartPayment(ctx context.Context, cmd StartPaymentCommand) (*PaymentSession, error)
} package alipayacl import ( "context" "fmt" "example/order"
) // 仅示意第三方 SDK 的能力边界，避免示例依赖真实包名。
type alipayPrecreateClient interface { Precreate(ctx context.Context, body map[string]any) (*alipayPrecreateResult, error)
} type alipayPrecreateResult struct { QRCodeURL string
} // AlipayACL 位于基础设施侧：翻译领域命令 ↔ 支付宝请求 / 响应。
type AlipayACL struct { client alipayPrecreateClient
} func NewAlipayACL(client alipayPrecreateClient) *AlipayACL { return &AlipayACL{client: client}
} func (a *AlipayACL) StartPayment(ctx context.Context, cmd order.StartPaymentCommand) (*order.PaymentSession, error) { req := map[string]any{ "out_trade_no": string(cmd.OrderID), "total_amount": cmd.Payable.DecimalYuan(), "subject": fmt.Sprintf("订单支付 %s", string(cmd.OrderID)), } resp, err := a.client.Precreate(ctx, req) if err != nil { return nil, err } return &order.PaymentSession{CheckoutURL: resp.QRCodeURL}, nil
} 收益 ： 当渠道字段变更时，修改集中在 ACL；订单聚合与用例不被第三方类型污染 可以为同一个端口提供多个实现（支付宝 ACL、微信 ACL、PayPal ACL），通过工厂模式或配置切换 测试时可以使用 Fake 实现替代真实支付渠道，提升测试速度和可靠性 防腐层承担了「翻译」职责，领域层保持纯粹，不受外部依赖污染 反模式警示 ：有些团队会在防腐层之外再包一层「防防腐层」，过度封装导致代码层级过深。原则是 一次翻译足矣 ——从第三方模型翻译到领域模型，中间不需要再多一层「通用模型」。

